208	pub(crate) fn check_exact_len(bytes: &[u8], expected: usize) -> Result<(), ParseError> {
209	    cycle_track("util/check_exact_len", || {
210	        if bytes.len() != expected {
211	            return Err(ParseError::InvalidLength {
212	                expected,
213	                actual: bytes.len(),
214	            });
215	        }
216	        Ok(())
217	    })
218	}
219	
220	pub(crate) fn check_aligned<T>(bytes: &[u8]) -> Result<(), ParseError> {
221	    cycle_track("util/check_aligned", || {
222	        let required = align_of::<T>();
223	        let address = bytes.as_ptr() as usize;
224	        if !address.is_multiple_of(required) {
225	            return Err(ParseError::Misaligned { required });
226	        }
227	        Ok(())
228	    })
229	}
