231	pub(crate) fn copy_from_bytes<T>(bytes: &[u8]) -> Result<T, ParseError> {
232	    cycle_track("util/copy_from_bytes", || {
233	        check_exact_len(bytes, size_of::<T>())?;
234	        let mut value = MaybeUninit::<T>::uninit();
235	        unsafe {
236	            ptr::copy_nonoverlapping(
237	                bytes.as_ptr(),
238	                value.as_mut_ptr() as *mut u8,
239	                size_of::<T>(),
240	            );
241	            Ok(value.assume_init())
242	        }
243	    })
244	}
245	
246	pub(crate) fn copy_to_bytes<const N: usize, T>(value: &T) -> [u8; N] {
247	    cycle_track("util/copy_to_bytes", || {
248	        assert_eq!(size_of::<T>(), N);
249	        let mut bytes = [0u8; N];
250	        unsafe {
251	            ptr::copy_nonoverlapping(value as *const T as *const u8, bytes.as_mut_ptr(), N);
252	        }
253	        bytes
254	    })
255	}
256	
257	pub(crate) fn slice_from_bytes<T>(bytes: &[u8]) -> Result<&[T], ParseError> {
258	    cycle_track("util/slice_from_bytes", || {
259	        if !bytes.len().is_multiple_of(size_of::<T>()) {
260	            return Err(ParseError::InvalidLength {
261	                expected: bytes.len().div_ceil(size_of::<T>()) * size_of::<T>(),
262	                actual: bytes.len(),
263	            });
264	        }
265	        check_aligned::<T>(bytes)?;
266	        Ok(unsafe {
267	            slice::from_raw_parts(bytes.as_ptr() as *const T, bytes.len() / size_of::<T>())
268	        })
269	    })
270	}
