365	/// This is committed only as a digest in the public values; the raw bytes are
366	/// supplied as a private witness when extending a proof.
367	///
368	/// Serialized without struct padding (116 bytes):
369	/// ```text
370	///  0..  4  current_nbits           u32 LE
371	///  4.. 36  current_work            [u64; 4] LE
372	/// 36.. 68  current_target          [u64; 4] LE
373	/// 68.. 72  epoch_start_timestamp   u32 LE
374	/// 72..116  timestamps              [u32; 11] LE
375	/// ```
376	#[repr(C)]
377	#[derive(Debug, Clone, PartialEq, Eq)]
378	pub struct PrivateContinuationState {
379	    pub current_nbits: CompactTarget,
380	    pub current_work: ChainWork,
381	    pub current_target: Target,
382	    pub epoch_start_timestamp: BlockTimestamp,
383	    pub timestamps: [BlockTimestamp; WINDOW_SIZE],
384	}
385	
386	/// Size of the serialized [`PrivateContinuationState`] in bytes (no padding).
387	pub const PRIVATE_CONTINUATION_STATE_SIZE: usize = 4 + 32 + 32 + 4 + 4 * WINDOW_SIZE;
388	
389	impl PrivateContinuationState {
390	    #[must_use]
391	    pub fn from_state(state: &State) -> Self {
392	        Self {
393	            current_nbits: state.current_nbits,
394	            current_work: state.current_work,
395	            current_target: state.current_target,
396	            epoch_start_timestamp: state.epoch_start_timestamp,
397	            timestamps: state.timestamps,
398	        }
399	    }
400	
401	    #[must_use]
402	    pub fn to_bytes(&self) -> [u8; PRIVATE_CONTINUATION_STATE_SIZE] {
403	        let mut out = [0u8; PRIVATE_CONTINUATION_STATE_SIZE];
404	        out[0..4].copy_from_slice(self.current_nbits.to_le_bytes_slice());
405	        out[4..36].copy_from_slice(self.current_work.to_le_bytes_slice());
406	        out[36..68].copy_from_slice(self.current_target.to_le_bytes_slice());
407	        out[68..72].copy_from_slice(self.epoch_start_timestamp.to_le_bytes_slice());
408	        for (i, ts) in self.timestamps.iter().enumerate() {
409	            out[72 + i * 4..72 + (i + 1) * 4].copy_from_slice(ts.to_le_bytes_slice());
410	        }
411	        out
412	    }
413	
414	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
415	        check_exact_len(bytes, PRIVATE_CONTINUATION_STATE_SIZE)?;
416	        let current_nbits = CompactTarget::new(u32::from_le_bytes(bytes[0..4].try_into().unwrap()));
417	        let current_work = ChainWork::from_le_bytes(bytes[4..36].try_into().unwrap());
418	        let current_target = Target::from_le_bytes(bytes[36..68].try_into().unwrap());
419	        let epoch_start_timestamp =
420	            BlockTimestamp::from_le_bytes(bytes[68..72].try_into().unwrap());
421	        let mut timestamps = [BlockTimestamp::default(); WINDOW_SIZE];
422	        for (i, ts) in timestamps.iter_mut().enumerate() {
423	            *ts = BlockTimestamp::from_le_bytes(
424	                bytes[72 + i * 4..72 + (i + 1) * 4].try_into().unwrap(),
425	            );
426	        }
427	        Ok(Self {
428	            current_nbits,
429	            current_work,
430	            current_target,
431	            epoch_start_timestamp,
432	            timestamps,
433	        })
434	    }
435	}
