503	/// Wire layout of the minimal public values committed by the prover.
504	///
505	/// Layout (169 bytes, little-endian):
506	/// ```text
507	///  0.. 32  genesis_hash        [u8; 32]
508	/// 32.. 64  tip_hash            [u8; 32]
509	/// 64.. 96  chain_work          [u8; 32]  (u256 LE)
510	/// 96..100  height              u32 LE
511	/// 100      return_code         u8  (0 = success, nonzero = failure)
512	/// 101..105 failure_height      u32 LE  (0 on success)
513	/// 105..137 continuation_digest [u8; 32]
514	/// 137..169 verifier_key         [u8; 32]  ([u32; 8] LE words)
515	/// ```
