518	/// and [`MinimalPublicValues::parse`] rather than transmuting.
519	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
520	pub struct MinimalPublicValues {
521	    pub genesis_hash: BlockHash,
522	    pub tip_hash: BlockHash,
523	    pub chain_work: [u8; 32],
524	    pub height: u32,
525	    pub return_code: u8,
526	    pub failure_height: u32,
527	    pub continuation_digest: [u8; 32],
