603	        let continuation_digest: [u8; 32] = bytes[105..137].try_into().unwrap();
604	        let verifier_key = VerifierKeyDigest::from_bytes(bytes[137..169].try_into().unwrap());
605	        Ok(Self {
606	            genesis_hash,
