740	/// Convert a full 256-bit target into compact `bits` encoding.
741	#[must_use]
742	pub fn target_to_bits(target: Target) -> CompactTarget {
743	    cycle_track("difficulty/target_to_bits", || {
744	        let bytes = target.to_le_bytes();
745	        let mut nbytes = 32usize;
746	        while nbytes > 0 && bytes[nbytes - 1] == 0 {
747	            nbytes -= 1;
748	        }
749	        if nbytes == 0 {
750	            return CompactTarget::new(0);
751	        }
752	
753	        let mut compact = if nbytes <= 3 {
754	            let mut value = 0u32;
755	            for i in (0..nbytes).rev() {
756	                value = (value << 8) | bytes[i] as u32;
757	            }
758	            value << (8 * (3 - nbytes))
759	        } else {
760	            ((bytes[nbytes - 1] as u32) << 16)
761	                | ((bytes[nbytes - 2] as u32) << 8)
762	                | (bytes[nbytes - 3] as u32)
763	        };
764	
765	        if (compact & 0x0080_0000) != 0 {
766	            compact >>= 8;
767	            nbytes += 1;
768	        }
769	
770	        CompactTarget::new(((nbytes as u32) << 24) | (compact & 0x007f_ffff))
771	    })
772	}
773	
774	/// Expand compact Bitcoin `bits` into a normalized full 256-bit target.
775	#[must_use]
776	pub fn target_from_bits(compact_target: CompactTarget) -> Target {
777	    cycle_track("difficulty/target_from_bits", || {
778	        let bits = compact_target.into_inner();
779	        let size = (bits >> 24) as usize;
780	        let mantissa = bits & 0x007f_ffff;
781	        let mut normalized_target_bytes = [0u8; 32];
782	
783	        if size <= 3 {
784	            let value = mantissa >> (8 * (3 - size));
785	            normalized_target_bytes[0..4].copy_from_slice(&value.to_le_bytes());
786	        } else {
787	            let offset = size - 3;
788	            if offset < 32 {
789	                normalized_target_bytes[offset] = (mantissa & 0xff) as u8;
790	            }
791	            if offset + 1 < 32 {
792	                normalized_target_bytes[offset + 1] = ((mantissa >> 8) & 0xff) as u8;
793	            }
794	            if offset + 2 < 32 {
795	                normalized_target_bytes[offset + 2] = ((mantissa >> 16) & 0xff) as u8;
796	            }
797	        }
798	
799	        Target::from_le_bytes(normalized_target_bytes)
800	    })
801	}
