811	impl core::ops::Add for ChainWork {
812	    type Output = Self;
813	
814	    fn add(self, rhs: Self) -> Self::Output {
815	        cycle_track("u256/add", || {
816	            let a = self.as_limbs();
817	            let b = rhs.as_limbs();
818	            let mut result = [0u64; 4];
819	            let mut carry = 0u128;
820	            for i in 0..4 {
821	                let sum = (a[i] as u128) + (b[i] as u128) + carry;
822	                result[i] = sum as u64;
823	                carry = sum >> 64;
824	            }
825	            ChainWork::from_limbs(result)
826	        })
827	    }
828	}
