882	/// Add one to a target, modifying the limbs in place.
883	///
884	/// A valid target can not be a max u256, so:
885	///   - It can't carry over into a 5th limb
886	///   - A carry can only start if the first limb is max u64
887	///   - A carry can only continue if the next limb is a max u64
888	///   - A max u64 with a carry-over of 1 becomes 0
889	///
890	/// We can iterate until we find a limb < max u64, add 1 to it, and we're done. As long as we find max u64 limbs we
891	/// just set them to 0 and move forward. Iterating fully without hitting a non-max u64 indicates that we have bad
892	/// data; the target is invalid and we return an error.
893	fn increment_target(target: &mut u256) -> Result<(), TargetError> {
894	    cycle_track("pow/work/target_plus_one", || {
895	        for (i, limb) in target.as_limbs_mut().iter_mut().enumerate() {
896	            // This limb isn't saturated so it can't carry; add 1 and we're done.
897	            if *limb < u64::MAX {
898	                *limb += 1;
899	                break;
900	            }
901	
902	            // If we're here at the last index then all limbs are saturated and the target is invalid.
903	            if i == 3 {
904	                return Err(TargetError::TargetTooLarge);
905	            }
906	
907	            // This limb is saturated but not the final limb, so roll it over to 0 and proceed with the carry
908	            *limb = 0;
909	        }
910	        Ok(())
911	    })
912	}
913	
914	/// Shift `value` left by one bit in place, returning the carry (the evicted MSB).
915	#[must_use]
916	fn shl1_with_carry(value: &mut u256) -> bool {
917	    cycle_track("pow/work/shl1_with_carry", || {
918	        let limbs = value.as_limbs_mut();
919	        let mut carry = 0u64;
920	        for limb in limbs.iter_mut() {
921	            let next_carry = *limb >> 63;
922	            *limb = (*limb << 1) | carry;
923	            carry = next_carry;
924	        }
925	        carry > 0
926	    })
927	}
