964	/// Compute the compact and normalized full target required at a difficulty boundary.
965	#[must_use]
966	pub fn calculate_next_target_required(
967	    old_target: Target,
968	    epoch_start_timestamp: BlockTimestamp,
969	    previous_timestamp: BlockTimestamp,
970	) -> (CompactTarget, Target) {
971	    cycle_track("pow/calculate_next_target_required", || {
972	        // Normalize the timespan to ensure it's within the min/max bounds allowed.
973	        let actual_timespan = i64::from(*previous_timestamp) - i64::from(*epoch_start_timestamp);
974	        let clamped_timespan = actual_timespan.clamp(MIN_EPOCH_TIMESPAN, MAX_EPOCH_TIMESPAN) as u32;
975	
976	        // Calculate the raw target value from the normalized previous target and the timespan.
977	        let mut target_limbs = old_target.into_inner().into_limbs();
978	        let mut carry = 0u128;
979	        for limb in &mut target_limbs {
980	            let product = (*limb as u128) * (clamped_timespan as u128) + carry;
981	            *limb = product as u64;
982	            carry = product >> 64;
983	        }
984	
985	        let mut remainder = 0u128;
986	        for limb in target_limbs.iter_mut().rev() {
987	            let value = (remainder << 64) | (*limb as u128);
988	            *limb = (value / (EXPECTED_EPOCH_TIMESPAN as u128)) as u64;
989	            remainder = value % (EXPECTED_EPOCH_TIMESPAN as u128);
990	        }
991	
992	        // Normalize the new target to ensure an upper-bound (a minimum difficulty) and to handle the implicit
993	        // truncation that occurs when round-tripping through the nbits format.
994	        let calculated_target = Target::from_limbs(target_limbs);
995	        let clamped_target = calculated_target.min(GENESIS_TARGET);
996	        let compact_target = target_to_bits(clamped_target);
997	        let normalized_target = target_from_bits(compact_target);
998	
999	        // The target is capped above and truncated below; return it and the compact form we calculated along the way.
1000	        (compact_target, normalized_target)
1001	    })
1002	}
