1034	    pub(crate) fn median_time_past(state: &State) -> BlockTimestamp {
1035	        let count = state.timestamp_count();
1036	        let mut sorted = state.timestamps;
1037	        if count >= WINDOW_SIZE {
1038	            sorted.sort_unstable();
1039	            sorted[WINDOW_SIZE / 2]
1040	        } else {
1041	            sorted[..count].sort_unstable();
1042	            sorted[count / 2]
1043	        }
1044	    }
