1051	                    version: 1,
1052	                    merkle_root: [0x22; 32],
1053	                    timestamp: ts(timestamp),
1054	                    nonce: 7,
1055	                }],
1056	                &[median_hint],
1057	                |_| zero_hash(),
1058	            )
1059	            .unwrap();
1060	    }
