1062	    fn median_hints_for_headers(
1063	        initial_state: &State,
1064	        headers: &[NewHeader],
1065	    ) -> Vec<BlockTimestamp> {
1066	        let mut state = initial_state.clone();
1067	        let mut medians = Vec::with_capacity(headers.len());
1068	        for header in headers {
1069	            medians.push(median_time_past(&state));
1070	            let timestamp_slot = (state.height as usize + 1) % WINDOW_SIZE;
1071	            state.timestamps[timestamp_slot] = header.timestamp;
1072	            state.height += 1;
1073	        }
1074	        medians
1075	    }
