1	use memory_usage::StageSample;
2	use sp1_sdk::prelude::*;
3	use sp1_sdk::ExecutionReport;
4	
5	use crate::memory_monitor;
6	use crate::pipeline::batch::PreparedBatch;
7	use crate::pipeline::diagnostics::{timed_async, timed_sync};
8	use crate::pipeline::input::{build_recursive_proof, build_stdin};
9	use crate::pipeline::BoxError;
10	use crate::pipeline::ELF;
11	use crate::util;
12	use crate::util::{HeaderChainPublicValues, Input, VerifierKeyDigest};
13	
14	pub(crate) struct ExecutedBatchArtifacts {
15	    pub(crate) stdin: SP1Stdin,
16	    pub(crate) expected_pv: Vec<u8>,
17	    pub(crate) before_prove_sample: StageSample,
18	    pub(crate) execution_report: ExecutionReport,
19	}
20	
21	pub(crate) struct UnprovenBatchInput<'a> {
22	    pub(crate) current_state: &'a util::State,
23	    pub(crate) headers: &'a [util::NewHeader],
24	    pub(crate) median_hints: &'a [util::BlockTimestamp],
25	    pub(crate) expected_state: &'a util::State,
26	    pub(crate) expected_continuation_digest: [u8; 32],
27	}
28	
29	pub(crate) fn verify_public_values(
30	    pv: &[u8],
31	    expected_pv: &[u8],
32	    label: &str,
33	) -> Result<(), BoxError> {
34	    let parsed = HeaderChainPublicValues::parse(pv).map_err(|err| err.to_string())?;
35	    match parsed {
36	        HeaderChainPublicValues::Success { .. } => {
37	            if pv != expected_pv {
38	                return Err(format!(
39	                    "{label} public values mismatch: expected {}, got {}",
40	                    hex::encode(expected_pv),
41	                    hex::encode(pv),
42	                )
43	                .into());
44	            }
45	            Ok(())
46	        }
47	        HeaderChainPublicValues::Failure { failure, .. } => Err(format!(
48	            "{label} ended in error {} at height {}",
49	            failure.error_code, failure.failure_height,
50	        )
51	        .into()),
52	    }
53	}
54	
55	pub(crate) async fn execute_batch_with_prover<P, K>(
56	    prover_name: &str,
57	    prover: &P,
58	    proving_key: &K,
59	    batch: &PreparedBatch,
60	) -> Result<ExecutedBatchArtifacts, BoxError>
61	where
62	    P: Prover<ProvingKey = K>,
63	    K: ProvingKey,
64	    P::Error: std::fmt::Display + Send + Sync + 'static,
65	{
66	    let expected_pv = util::MinimalPublicValues::success(
67	        &batch.expected_state.public_claim(),
68	        batch.expected_continuation_digest,
69	        VerifierKeyDigest::from_raw(proving_key.verifying_key().hash_u32()),
70	    )
71	    .to_bytes()
72	    .to_vec();
73	    let recursive_proof = timed_sync("build_recursive_proof", || {
74	        build_recursive_proof(proving_key.verifying_key(), batch.previous_proof.as_ref())
75	    })?;
76	    let input = Input::new(batch.current_state.public_claim(), recursive_proof);
77	    let stdin = timed_sync("serialize_input", || {
78	        build_stdin(
79	            &input,
80	            &batch.current_state,
81	            &batch.headers,
82	            &batch.median_hints,
83	            batch
84	                .previous_proof
85	                .as_ref()
86	                .map(|p| (p, proving_key.verifying_key())),
87	        )
88	    })?;
89	
90	    let (public_values, report) = timed_async("execute_program", || async {
91	        prover
92	            .execute(ELF, stdin.clone())
93	            .deferred_proof_verification(false)
94	            .await
95	            .map_err(|err| -> BoxError { err.to_string().into() })
96	    })
97	    .await?;
98	    tracing::info!(prover = prover_name, "Execution completed");
99	
100	    let execution_public_values = public_values.to_vec();
101	    match HeaderChainPublicValues::parse(&execution_public_values) {
102	        Ok(HeaderChainPublicValues::Success { .. }) => {
103	            timed_sync(
104	                "verify_execution_public_values",
105	                || -> Result<(), BoxError> {
106	                    verify_public_values(&execution_public_values, &expected_pv, "execution")
107	                },
108	            )?;
109	        }
110	        Ok(HeaderChainPublicValues::Failure { failure, .. }) => {
111	            return Err(format!(
112	                "execution failed with {} at height {}",
113	                failure.error_code, failure.failure_height
114	            )
115	            .into());
116	        }
117	        Err(err) => {
118	            return Err(format!("execution produced malformed public values: {err}").into());
119	        }
120	    }
121	
122	    let before_prove_sample =
123	        memory_monitor::log_point("after_execute", "Memory snapshot after VM execution");
124	
125	    Ok(ExecutedBatchArtifacts {
126	        stdin,
127	        expected_pv,
128	        before_prove_sample,
129	        execution_report: report,
130	    })
131	}
132	
133	pub(crate) async fn execute_batch_without_proof<P>(
134	    prover: &P,
135	    batch: UnprovenBatchInput<'_>,
136	) -> Result<ExecutedBatchArtifacts, BoxError>
137	where
138	    P: Prover,
139	    P::Error: std::fmt::Display + Send + Sync + 'static,
140	{
141	    let verifier_key = VerifierKeyDigest::default();
142	    let expected_pv = util::MinimalPublicValues::success(
