use sp1_sdk::prelude::*;
use sp1_sdk::SP1Proof;
use std::collections::HashMap;
use std::env::VarError;
use std::path::PathBuf;

use crate::config::db_path;
use crate::pipeline::{BoxError, ProofGenerationConfig, ProverBackend};
use crate::util;
use crate::util::{Input, PublicValuesDigest, RecursiveProof, VerifierKeyDigest};

const GENESIS_HASH_HEX: &str = "000000000019d6689c085ae165831e934ff763ae46a2a6c172b3f1b60a8ce26f";

pub const ENV_ZKPOW_BATCH_SIZE: &str = "ZKPOW_BATCH_SIZE";
pub const ENV_ZKPOW_BATCH_COUNT: &str = "ZKPOW_BATCH_COUNT";
pub const ENV_ZKPOW_OUTPUT_DIR: &str = "ZKPOW_OUTPUT_DIR";
pub const ENV_ZKPOW_DB_PATH: &str = "ZKPOW_DB_PATH";
pub const ENV_ZKPOW_PREV_PROOF: &str = "ZKPOW_PREV_PROOF";
pub const ENV_ZKPOW_SHOW_COMPRESSED_PROOF_SPANS: &str = "ZKPOW_SHOW_COMPRESSED_PROOF_SPANS";

pub const ENV_ZKPOW_EXECUTE_ONLY: &str = "ZKPOW_EXECUTE_ONLY";
pub const ENV_ZKPOW_GENERATE_GROTH16: &str = "ZKPOW_GENERATE_GROTH16";

pub const ENV_ZKPOW_USE_CUDA: &str = "ZKPOW_USE_CUDA";
pub const ENV_ZKPOW_CUDA_DEVICE_ID: &str = "ZKPOW_CUDA_DEVICE_ID";

const DEFAULT_BATCH_SIZE: u32 = 2016;
const DEFAULT_BATCH_COUNT: u32 = 500;

pub(crate) trait EnvSource {
    fn get(&self, var_name: &str) -> Result<String, VarError>;
}

#[derive(Debug, Clone, Copy)]
pub struct ProcessEnv;

impl EnvSource for ProcessEnv {
    fn get(&self, var_name: &str) -> Result<String, VarError> {
        std::env::var(var_name)
    }
}

#[derive(Debug, Clone, Default)]
pub struct MapEnvSource {
    values: HashMap<String, String>,
}

impl MapEnvSource {
    pub fn new(values: HashMap<String, String>) -> Self {
        Self { values }
    }
}

impl EnvSource for MapEnvSource {
    fn get(&self, var_name: &str) -> Result<String, VarError> {
        self.values
            .get(var_name)
            .cloned()
            .ok_or(VarError::NotPresent)
    }
}

pub fn parse_genesis_hash() -> Result<util::BlockHash, BoxError> {
    let mut genesis_hash: [u8; 32] = hex::decode(GENESIS_HASH_HEX)
        .map_err(|err| format!("invalid genesis hash hex: {}", err))?
        .try_into()
        .map_err(|_| "genesis hash should be 32 bytes")?;
    genesis_hash.reverse();
    Ok(util::BlockHash::new(genesis_hash))
}

pub(crate) fn parse_bool_env(
    source: &impl EnvSource,
    var_name: &'static str,
) -> Result<bool, BoxError> {
    parse_bool_env_or(source, var_name, false)
}

pub(crate) fn parse_bool_env_or(
    source: &impl EnvSource,
    var_name: &'static str,
    default: bool,
) -> Result<bool, BoxError> {
    match source.get(var_name) {
        Ok(value) => match value.to_ascii_lowercase().as_str() {
            "1" | "true" | "yes" | "on" => Ok(true),
            "0" | "false" | "no" | "off" => Ok(false),
            _ => Err(format!(
                "invalid {var_name} value `{value}`; expected one of 1,true,yes,on,0,false,no,off"
            )
            .into()),
        },
        Err(VarError::NotPresent) => Ok(default),
        Err(err) => Err(err.into()),
    }
}

pub(crate) fn parse_u32_env(
    source: &impl EnvSource,
    var_name: &'static str,
) -> Result<Option<u32>, BoxError> {
    match source.get(var_name) {
        Ok(value) => {
            Ok(Some(value.parse().map_err(|err| {
                format!("invalid {var_name} value `{value}`: {err}")
            })?))
        }
        Err(VarError::NotPresent) => Ok(None),
        Err(err) => Err(err.into()),
    }
}

fn parse_u32_env_or(
    source: &impl EnvSource,
    var_name: &'static str,
    default: u32,
) -> Result<u32, BoxError> {
    Ok(parse_u32_env(source, var_name)?.unwrap_or(default))
}

fn parse_path_env<E: EnvSource>(source: &E, var_name: &'static str) -> Option<PathBuf> {
    source.get(var_name).ok().map(PathBuf::from)
}

pub(crate) fn ensure_cuda_requested_configuration(
    use_cuda: bool,
    cuda_device_id: Option<u32>,
) -> Result<ProverBackend, BoxError> {
    if !use_cuda {
        if cuda_device_id.is_some() {
            return Err(format!(
                "{ENV_ZKPOW_CUDA_DEVICE_ID} is only valid when {ENV_ZKPOW_USE_CUDA}=1"
            )
            .into());
        }
        return Ok(ProverBackend::Cpu);
    }

    #[cfg(feature = "CUDA")]
    {
        return Ok(ProverBackend::Cuda);
    }

    #[cfg(not(feature = "CUDA"))]
    let _ = cuda_device_id;
    #[cfg(not(feature = "CUDA"))]
    Err(
        format!("{ENV_ZKPOW_USE_CUDA}=1 requires building zkpow-host with `--features CUDA`")
            .into(),
    )
}

pub(crate) fn config_from_source(
    source: &impl EnvSource,
) -> Result<ProofGenerationConfig, BoxError> {
    let use_cuda = parse_bool_env(source, ENV_ZKPOW_USE_CUDA)?;
    let cuda_device_id = parse_u32_env(source, ENV_ZKPOW_CUDA_DEVICE_ID)?;

    let execute_only = parse_bool_env(source, ENV_ZKPOW_EXECUTE_ONLY)?;
    let generate_groth16 = parse_bool_env(source, ENV_ZKPOW_GENERATE_GROTH16)?;
    if execute_only && generate_groth16 {
        return Err(format!(
            "{ENV_ZKPOW_GENERATE_GROTH16} cannot be enabled when {ENV_ZKPOW_EXECUTE_ONLY}=1"
        )
        .into());
    }

    let num_headers = parse_u32_env_or(source, ENV_ZKPOW_BATCH_SIZE, DEFAULT_BATCH_SIZE)?;
    let batch_count = parse_u32_env_or(source, ENV_ZKPOW_BATCH_COUNT, DEFAULT_BATCH_COUNT)?;

    let configured_backend = ensure_cuda_requested_configuration(use_cuda, cuda_device_id)?;
    let prover_backend = if execute_only && configured_backend == ProverBackend::Cpu {
        ProverBackend::Mock
    } else {
        configured_backend
    };

    Ok(ProofGenerationConfig {
        prev_proof_path: parse_path_env(source, ENV_ZKPOW_PREV_PROOF),
        trusted_start_height: None,
        num_headers,
        batch_count,
        db_path: parse_path_env(source, ENV_ZKPOW_DB_PATH)
            .unwrap_or_else(|| PathBuf::from(db_path())),
        output_dir: parse_path_env(source, ENV_ZKPOW_OUTPUT_DIR)
            .unwrap_or_else(|| PathBuf::from(".")),
        generate_groth16,
        execute_only,
        prover_backend,
        cuda_device_id,
    })
}

pub fn config_from_env() -> Result<ProofGenerationConfig, BoxError> {
    config_from_source(&ProcessEnv)
}

pub fn build_recursive_proof(
    vk: &sp1_prover::SP1VerifyingKey,
    previous_proof: Option<&SP1ProofWithPublicValues>,
) -> Result<RecursiveProof, BoxError> {
    let verifier_key = VerifierKeyDigest::from_raw(vk.hash_u32());
    Ok(if let Some(prev_proof_val) = previous_proof {
        let pv_bytes = prev_proof_val.public_values.to_vec();
        let previous_return_code = match zkpow_core::HeaderChainPublicValues::parse(&pv_bytes) {
            Ok(zkpow_core::HeaderChainPublicValues::Success { .. }) => 0u8,
            Ok(zkpow_core::HeaderChainPublicValues::Failure { failure, .. }) => {
                failure.error_code.as_byte()
            }
            Err(e) => {
                return Err(format!("failed to parse previous proof public values: {}", e).into())
            }
        };
        RecursiveProof {
            verifier_key,
            public_values_digest: PublicValuesDigest::from_raw(util::compute_pv_digest(&pv_bytes)),
            previous_return_code,
            ..Default::default()
        }
    } else {
        RecursiveProof {
            verifier_key,
            ..Default::default()
        }
    })
}

pub fn build_stdin(
    input: &Input,
    state: &util::State,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    previous_proof: Option<(&SP1ProofWithPublicValues, &sp1_prover::SP1VerifyingKey)>,
) -> Result<SP1Stdin, BoxError> {
    let mut stdin = SP1Stdin::new();
    stdin.write_vec(input.to_bytes());
    stdin.write_vec(state.to_bytes().to_vec());
    stdin.write_vec(zkpow_core::serialize_new_headers(headers));
    stdin.write_vec(zkpow_core::serialize_median_hints(median_hints));

    if let Some((prev_proof, vk)) = previous_proof {
        let SP1Proof::Compressed(inner_proof) = &prev_proof.proof else {
            return Err("previous proof is not compressed".into());
        };
        stdin.write_proof(inner_proof.as_ref().clone(), vk.vk.clone());
    }

    Ok(stdin)
}

use memory_usage::StageSample;
use sp1_sdk::prelude::*;
use sp1_sdk::ExecutionReport;

use crate::memory_monitor;
use crate::pipeline::batch::PreparedBatch;
use crate::pipeline::diagnostics::{timed_async, timed_sync};
use crate::pipeline::input::{build_recursive_proof, build_stdin};
use crate::pipeline::BoxError;
use crate::pipeline::ELF;
use crate::util;
use crate::util::{HeaderChainPublicValues, Input, VerifierKeyDigest};

pub(crate) struct ExecutedBatchArtifacts {
    pub(crate) stdin: SP1Stdin,
    pub(crate) expected_pv: Vec<u8>,
    pub(crate) before_prove_sample: StageSample,
    pub(crate) execution_report: ExecutionReport,
}

pub(crate) struct UnprovenBatchInput<'a> {
    pub(crate) current_state: &'a util::State,
    pub(crate) headers: &'a [util::NewHeader],
    pub(crate) median_hints: &'a [util::BlockTimestamp],
    pub(crate) expected_state: &'a util::State,
    pub(crate) expected_continuation_digest: [u8; 32],
}

pub(crate) fn verify_public_values(
    pv: &[u8],
    expected_pv: &[u8],
    label: &str,
) -> Result<(), BoxError> {
    let parsed = HeaderChainPublicValues::parse(pv).map_err(|err| err.to_string())?;
    match parsed {
        HeaderChainPublicValues::Success { .. } => {
            if pv != expected_pv {
                return Err(format!(
                    "{label} public values mismatch: expected {}, got {}",
                    hex::encode(expected_pv),
                    hex::encode(pv),
                )
                .into());
            }
            Ok(())
        }
        HeaderChainPublicValues::Failure { failure, .. } => Err(format!(
            "{label} ended in error {} at height {}",
            failure.error_code, failure.failure_height,
        )
        .into()),
    }
}

pub(crate) async fn execute_batch_with_prover<P, K>(
    prover_name: &str,
    prover: &P,
    proving_key: &K,
    batch: &PreparedBatch,
) -> Result<ExecutedBatchArtifacts, BoxError>
where
    P: Prover<ProvingKey = K>,
    K: ProvingKey,
    P::Error: std::fmt::Display + Send + Sync + 'static,
{
    let expected_pv = util::MinimalPublicValues::success(
        &batch.expected_state.public_claim(),
        batch.expected_continuation_digest,
        VerifierKeyDigest::from_raw(proving_key.verifying_key().hash_u32()),
    )
    .to_bytes()
    .to_vec();
    let recursive_proof = timed_sync("build_recursive_proof", || {
        build_recursive_proof(proving_key.verifying_key(), batch.previous_proof.as_ref())
    })?;
    let input = Input::new(batch.current_state.public_claim(), recursive_proof);
    let stdin = timed_sync("serialize_input", || {
        build_stdin(
            &input,
            &batch.current_state,
            &batch.headers,
            &batch.median_hints,
            batch
                .previous_proof
                .as_ref()
                .map(|p| (p, proving_key.verifying_key())),
        )
    })?;

    let (public_values, report) = timed_async("execute_program", || async {
        prover
            .execute(ELF, stdin.clone())
            .deferred_proof_verification(false)
            .await
            .map_err(|err| -> BoxError { err.to_string().into() })
    })
    .await?;
    tracing::info!(prover = prover_name, "Execution completed");

    let execution_public_values = public_values.to_vec();
    match HeaderChainPublicValues::parse(&execution_public_values) {
        Ok(HeaderChainPublicValues::Success { .. }) => {
            timed_sync(
                "verify_execution_public_values",
                || -> Result<(), BoxError> {
                    verify_public_values(&execution_public_values, &expected_pv, "execution")
                },
            )?;
        }
        Ok(HeaderChainPublicValues::Failure { failure, .. }) => {
            return Err(format!(
                "execution failed with {} at height {}",
                failure.error_code, failure.failure_height
            )
            .into());
        }
        Err(err) => {
            return Err(format!("execution produced malformed public values: {err}").into());
        }
    }

    let before_prove_sample =
        memory_monitor::log_point("after_execute", "Memory snapshot after VM execution");

    Ok(ExecutedBatchArtifacts {
        stdin,
        expected_pv,
        before_prove_sample,
        execution_report: report,
    })
}

pub(crate) async fn execute_batch_without_proof<P>(
    prover: &P,
    batch: UnprovenBatchInput<'_>,
) -> Result<ExecutedBatchArtifacts, BoxError>
where
    P: Prover,
    P::Error: std::fmt::Display + Send + Sync + 'static,
{
    let verifier_key = VerifierKeyDigest::default();
    let expected_pv = util::MinimalPublicValues::success(
        &batch.expected_state.public_claim(),
        batch.expected_continuation_digest,
        verifier_key,
    )
    .to_bytes()
    .to_vec();
    let continuation_digest = util::continuation_digest_from_state(batch.current_state);
    let prior_public_values = util::MinimalPublicValues::success(
        &batch.current_state.public_claim(),
        continuation_digest,
        verifier_key,
    );
    let recursive_proof = util::RecursiveProof {
        verifier_key,
        public_values_digest: util::PublicValuesDigest::from_raw(util::compute_pv_digest(
            &prior_public_values.to_bytes(),
        )),
        ..Default::default()
    };
    let input = Input::new(batch.current_state.public_claim(), recursive_proof);
    let stdin = timed_sync("serialize_input", || {
        build_stdin(
            &input,
            batch.current_state,
            batch.headers,
            batch.median_hints,
            None,
        )
    })?;

    let (public_values, report) = timed_async("execute_program", || async {
        prover
            .execute(ELF, stdin.clone())
            .deferred_proof_verification(false)
            .await
            .map_err(|err| -> BoxError { err.to_string().into() })
    })
    .await?;

    let execution_public_values = public_values.to_vec();
    verify_public_values(&execution_public_values, &expected_pv, "execution")?;

    let before_prove_sample =
        memory_monitor::log_point("after_execute", "Memory snapshot after VM execution");

    Ok(ExecutedBatchArtifacts {
        stdin,
        expected_pv,
        before_prove_sample,
        execution_report: report,
    })
}

use std::path::Path;

use super::{
    hash_header, target_from_bits, work_from_target, BlockHash, BlockTimestamp, ChainWork,
    CompactTarget, Header, NewHeader, PublicChainClaim, State, Target, GENESIS_TARGET,
};

// =============================================================================
// Data types
// =============================================================================

#[derive(Debug, Clone)]
pub struct HeaderRecord {
    pub height: u64,
    pub header: Header,
    pub chain_work: ChainWork,
    pub median_time_past: BlockTimestamp,
}

impl HeaderRecord {
    pub fn public_claim(&self, genesis_hash: BlockHash) -> PublicChainClaim {
        PublicChainClaim {
            genesis_hash,
            tip_hash: hash_header(&self.header),
            chain_work: self.chain_work,
            height: self.height as u32,
        }
    }
}

#[derive(Debug, Clone)]
pub struct HeaderBatchWitness {
    pub headers: Vec<NewHeader>,
    pub median_time_past_hints: Vec<BlockTimestamp>,
}

// =============================================================================
// Database configuration and connection
// =============================================================================

/// Holds the path to the SQLite database. Call `.connect()` to open a session.
#[derive(Debug, Clone)]
pub struct DbConfig {
    pub path: std::path::PathBuf,
}

impl DbConfig {
    pub fn new(path: impl AsRef<Path>) -> Self {
        Self {
            path: path.as_ref().to_path_buf(),
        }
    }

    pub fn connect(&self) -> Result<DbConn, rusqlite::Error> {
        let conn = rusqlite::Connection::open(&self.path)?;
        Ok(DbConn { conn })
    }
}

/// An open database connection. Caches prepared statements via `prepare_cached`.
pub struct DbConn {
    conn: rusqlite::Connection,
}

impl DbConn {
    pub fn load_public_claim(&self, height: u64, genesis_hash: BlockHash) -> PublicChainClaim {
        const SQL: &str = "SELECT block_hash, chainwork FROM headers WHERE height = ?1";

        let mut stmt = self
            .conn
            .prepare_cached(SQL)
            .expect("failed to prepare statement");
        stmt.query_row(rusqlite::params![height], |row| {
            let block_hash: Vec<u8> = row.get(0)?;
            let chainwork: Vec<u8> = row.get(1)?;

            Ok(PublicChainClaim {
                genesis_hash,
                tip_hash: BlockHash::new(
                    block_hash.try_into().expect("block_hash must be 32 bytes"),
                ),
                chain_work: chain_work_from_db_bytes(&chainwork),
                height: height as u32,
            })
        })
        .expect("failed to read public claim from database")
    }

    pub fn load_compact_target(&self, height: u64) -> CompactTarget {
        const SQL: &str = "SELECT n_bits FROM headers WHERE height = ?1";

        let mut stmt = self
            .conn
            .prepare_cached(SQL)
            .expect("failed to prepare statement");
        stmt.query_row(rusqlite::params![height], |row| {
            let nbits: i64 = row.get(0)?;
            Ok(CompactTarget::new(nbits as u32))
        })
        .expect("failed to read compact target from database")
    }

    pub fn load_header_records(&self, start_height: u64, count: u64) -> Vec<HeaderRecord> {
        const SQL: &str =
            "SELECT height, version, prev, merkle_root, timestamp, n_bits, nonce, chainwork, \
             median_time_past FROM headers \
             WHERE height >= ?1 AND height < ?2 ORDER BY height ASC";

        let mut stmt = self
            .conn
            .prepare_cached(SQL)
            .expect("failed to prepare statement");
        let end_height = start_height + count;
        let rows = stmt
            .query_map(rusqlite::params![start_height, end_height], |row| {
                let height: i64 = row.get(0)?;
                let version: i64 = row.get(1)?;
                let prev: Vec<u8> = row.get(2)?;
                let merkle_root: Vec<u8> = row.get(3)?;
                let timestamp: i64 = row.get(4)?;
                let nbits: i64 = row.get(5)?;
                let nonce: i64 = row.get(6)?;
                let chainwork: Vec<u8> = row.get(7)?;
                let median_time_past: i64 = row.get(8)?;

                let header = Header {
                    version: version as u32,
                    prev_blockhash: BlockHash::new(prev.try_into().expect("prev must be 32 bytes")),
                    merkle_root: merkle_root
                        .try_into()
                        .expect("merkle_root must be 32 bytes"),
                    timestamp: BlockTimestamp::new(timestamp as u32),
                    compact_target: CompactTarget::new(nbits as u32),
                    nonce: nonce as u32,
                };

                Ok(HeaderRecord {
                    height: height as u64,
                    header,
                    chain_work: chain_work_from_db_bytes(&chainwork),
                    median_time_past: BlockTimestamp::new(median_time_past as u32),
                })
            })
            .expect("failed to execute query");

        let mut records = Vec::with_capacity(count as usize);
        for row_result in rows {
            records.push(row_result.expect("failed to read header record from database"));
        }
        records
    }

    pub fn load_header_record(&self, height: u64) -> HeaderRecord {
        self.load_header_records(height, 1)
            .into_iter()
            .next()
            .expect("exactly one header record should be returned")
    }

    pub fn load_new_headers(&self, start_height: u64, count: u64) -> Vec<NewHeader> {
        self.load_header_batch_witness(start_height, count).headers
    }

    pub fn load_header_batch_witness(&self, start_height: u64, count: u64) -> HeaderBatchWitness {
        const SQL: &str =
            "SELECT version, merkle_root, timestamp, nonce, median_time_past FROM headers \
             WHERE height >= ?1 AND height < ?2 ORDER BY height ASC";

        let mut stmt = self
            .conn
            .prepare_cached(SQL)
            .expect("failed to prepare statement");
        let end_height = start_height + count;
        let rows = stmt
            .query_map(rusqlite::params![start_height, end_height], |row| {
                let version: i64 = row.get(0)?;
                let merkle_root: Vec<u8> = row.get(1)?;
                let timestamp: i64 = row.get(2)?;
                let nonce: i64 = row.get(3)?;
                let median_time_past: i64 = row.get(4)?;

                Ok((
                    NewHeader {
                        version: version as u32,
                        merkle_root: merkle_root
                            .try_into()
                            .expect("merkle_root must be 32 bytes"),
                        timestamp: BlockTimestamp::new(timestamp as u32),
                        nonce: nonce as u32,
                    },
                    BlockTimestamp::new(median_time_past as u32),
                ))
            })
            .expect("failed to execute batch witness query");

        let mut headers = Vec::with_capacity(count as usize);
        let mut median_time_past_hints = Vec::with_capacity(count as usize);
        for row_result in rows {
            let (header, median_time_past) =
                row_result.expect("failed to read header witness row from database");
            headers.push(header);
            median_time_past_hints.push(median_time_past);
        }

        HeaderBatchWitness {
            headers,
            median_time_past_hints,
        }
    }
}

fn chain_work_from_db_bytes(bytes: &[u8]) -> ChainWork {
    let raw: [u8; 32] = bytes.try_into().expect("chainwork must be 32 bytes");
    let mut little_endian = raw;
    little_endian.reverse();
    ChainWork::from_le_bytes(little_endian)
}

// =============================================================================
// Free functions
// =============================================================================

pub fn genesis_state_from_record(genesis: HeaderRecord, genesis_hash: BlockHash) -> State {
    let block_hash = hash_header(&genesis.header);
    assert_eq!(
        block_hash, genesis_hash,
        "configured genesis hash must match the supplied genesis header",
    );
    let genesis_work = work_from_target(GENESIS_TARGET).expect("GENESIS_TARGET is a valid target");

    let mut timestamps = [BlockTimestamp::default(); zkpow_core::WINDOW_SIZE];
    timestamps[0] = genesis.header.timestamp;

    State {
        header: genesis.header,
        block_hash,
        genesis_hash,
        current_nbits: genesis.header.compact_target,
        height: genesis.height as u32,
        chain_work: genesis.chain_work,
        current_work: genesis_work,
        current_target: GENESIS_TARGET,
        epoch_start_timestamp: genesis.header.timestamp,
        timestamps,
    }
}

pub fn state_from_db_at_height(db: &DbConn, height: u32, genesis_hash: BlockHash) -> State {
    if height == 0 {
        let genesis = db.load_header_record(0);
        return genesis_state_from_record(genesis, genesis_hash);
    }

    let current = db.load_header_record(height as u64);
    let epoch_start_height = (height / zkpow_core::EPOCH_LENGTH) * zkpow_core::EPOCH_LENGTH;
    let epoch_start_record = db.load_header_record(epoch_start_height as u64);
    let window_count = (height as usize + 1).min(zkpow_core::WINDOW_SIZE) as u64;
    let window_start = height as u64 + 1 - window_count;
    let window_records = db.load_header_records(window_start, window_count);

    let mut timestamps = [BlockTimestamp::default(); zkpow_core::WINDOW_SIZE];
    for record in window_records {
        timestamps[record.height as usize % zkpow_core::WINDOW_SIZE] = record.header.timestamp;
    }

    let current_target: Target = target_from_bits(current.header.compact_target);

    State {
        header: current.header,
        block_hash: hash_header(&current.header),
        genesis_hash,
        current_nbits: current.header.compact_target,
        height,
        chain_work: current.chain_work,
        current_work: work_from_target(current_target).expect("DB target must be a valid target"),
        current_target,
        epoch_start_timestamp: epoch_start_record.header.timestamp,
        timestamps,
    }
}

use std::path::PathBuf;

use sp1_sdk::SP1ProofWithPublicValues;

use crate::pipeline::diagnostics::{format_claim_mismatch, timed_sync};
use crate::pipeline::BoxError;
use crate::util;
use crate::util::{DbConn, HeaderChainPublicValues};

pub const NO_HEADERS_REMAINING_PREFIX: &str = "no headers remaining in database";

#[derive(Debug)]
pub struct PreparedBatch {
    pub previous_proof: Option<SP1ProofWithPublicValues>,
    pub current_state: util::State,
    pub headers: Vec<util::NewHeader>,
    pub median_hints: Vec<util::BlockTimestamp>,
    pub expected_state: util::State,
    pub expected_continuation_digest: [u8; 32],
    pub first_new_height: u32,
    pub end_height: u32,
}

pub fn prepare_batch(
    prev_proof_path: Option<&PathBuf>,
    trusted_start_height: Option<u32>,
    num_headers: u32,
    db: &DbConn,
    genesis_hash: util::BlockHash,
) -> Result<PreparedBatch, BoxError> {
    let previous_proof = load_optional_proof(prev_proof_path)?;
    let current_state = resolve_current_state(
        trusted_start_height,
        db,
        genesis_hash,
        previous_proof.as_ref(),
    )?;
    let first_new_height = current_state.height + 1;
    let witness = load_header_witness(num_headers, db, first_new_height)?;
    if witness.headers.is_empty() {
        return Err(format!(
            "{NO_HEADERS_REMAINING_PREFIX}: starting at height {}",
            first_new_height
        )
        .into());
    }
    let loaded_count = witness.headers.len() as u32;
    let end_height = current_state.height + loaded_count;
    let expected_state = simulate_expected_state(
        db,
        genesis_hash,
        &current_state,
        &witness.headers,
        &witness.median_time_past_hints,
        first_new_height,
        end_height,
    )?;
    let expected_continuation_digest = util::continuation_digest_from_state(&expected_state);

    Ok(PreparedBatch {
        previous_proof,
        current_state,
        headers: witness.headers,
        median_hints: witness.median_time_past_hints,
        expected_state,
        expected_continuation_digest,
        first_new_height,
        end_height,
    })
}

fn load_optional_proof(
    optional_proof: Option<&PathBuf>,
) -> Result<Option<SP1ProofWithPublicValues>, BoxError> {
    timed_sync("load_optional_proof", || {
        optional_proof
            .map(SP1ProofWithPublicValues::load)
            .transpose()
    })
}

fn resolve_current_state(
    trusted_start_height: Option<u32>,
    db: &DbConn,
    genesis_hash: util::BlockHash,
    previous_proof: Option<&SP1ProofWithPublicValues>,
) -> Result<util::State, BoxError> {
    timed_sync("resolve_current_state", || -> Result<_, BoxError> {
        if let Some(prev_proof) = previous_proof {
            if trusted_start_height.is_some() {
                return Err("trusted start height cannot be combined with a previous proof".into());
            }
            let prev_public_values =
                HeaderChainPublicValues::parse(prev_proof.public_values.as_ref())
                    .map_err(|err| err.to_string())?;
            let claim = match prev_public_values {
                HeaderChainPublicValues::Success { claim, .. } => claim,
                HeaderChainPublicValues::Failure { failure, .. } => {
                    return Err(format!(
                        "previous proof ended in error: {} at height {}",
                        failure.error_code, failure.failure_height,
                    )
                    .into());
                }
            };
            if claim.genesis_hash != genesis_hash {
                return Err("previous proof genesis mismatch".into());
            }

            let state = util::state_from_db_at_height(db, claim.height, genesis_hash);
            if state.public_claim() != claim {
                return Err(format!(
                    "db state mismatch at height {}:\n{}",
                    claim.height,
                    format_claim_mismatch(&claim, &state.public_claim())
                )
                .into());
            }
            return Ok(state);
        }

        if let Some(height) = trusted_start_height {
            return Ok(util::state_from_db_at_height(db, height, genesis_hash));
        }

        Ok(util::state_from_db_at_height(db, 0, genesis_hash))
    })
}

fn load_header_witness(
    num_headers: u32,
    db: &DbConn,
    first_new_height: u32,
) -> Result<util::HeaderBatchWitness, BoxError> {
    timed_sync("load_header_witness", || -> Result<_, BoxError> {
        Ok(db.load_header_batch_witness(first_new_height as u64, num_headers as u64))
    })
}

fn simulate_expected_state(
    db: &DbConn,
    genesis_hash: util::BlockHash,
    current_state: &util::State,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    first_new_height: u32,
    end_height: u32,
) -> Result<util::State, BoxError> {
    let expected_state = timed_sync("simulate_expected_state", || -> Result<_, BoxError> {
        Ok(util::compute_final_state_with_hints(
            current_state,
            headers,
            median_hints,
        ))
    })?;

    let db_end_claim = timed_sync("load_db_end_claim", || -> Result<_, BoxError> {
        Ok(db.load_public_claim(end_height as u64, genesis_hash))
    })?;

    if expected_state.public_claim() == db_end_claim {
        return Ok(expected_state);
    }

    let (bad_index, actual_state) = timed_sync("bisect_divergence", || -> Result<_, BoxError> {
        Ok(find_first_diverging_state(
            current_state,
            headers,
            median_hints,
            first_new_height,
            db,
            genesis_hash,
        ))
    })?;

    let bad_height = first_new_height + (bad_index as u32);
    let expected_claim = db.load_public_claim(bad_height as u64, genesis_hash);
    let actual_claim = actual_state.public_claim();

    Err(format!(
        "host simulation diverges from database\n  first bad header index in batch: {}\n  bad height: {}\n{}",
        bad_index,
        bad_height,
        format_claim_mismatch(&actual_claim, &expected_claim),
    )
    .into())
}

fn find_first_diverging_state(
    current_state: &util::State,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    first_new_height: u32,
    db: &DbConn,
    genesis_hash: util::BlockHash,
) -> (usize, util::State) {
    assert!(
        !headers.is_empty(),
        "find_first_diverging_state requires at least one header"
    );
    assert_eq!(
        headers.len(),
        median_hints.len(),
        "median hint count must match header count"
    );

    let mut replay_state = current_state.clone();
    let mut replayed_states = Vec::new();
    let mut lo = 0usize;
    let mut hi = headers.len() - 1;

    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        replay_states_through(
            &mut replay_state,
            &mut replayed_states,
            headers,
            median_hints,
            mid,
        );

        let height = first_new_height + (mid as u32);
        let db_claim = db.load_public_claim(height as u64, genesis_hash);
        if replayed_states[mid].public_claim() == db_claim {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }

    replay_states_through(
        &mut replay_state,
        &mut replayed_states,
        headers,
        median_hints,
        lo,
    );

    (lo, replayed_states[lo].clone())
}

fn replay_states_through(
    state: &mut util::State,
    replayed_states: &mut Vec<util::State>,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    target_index: usize,
) {
    while replayed_states.len() <= target_index {
        let index = replayed_states.len();
        state
            .apply_headers(&[headers[index]], &[median_hints[index]], util::hash_header)
            .unwrap_or_else(|err| {
                panic!("host state transition should succeed at header index {index}: {err:?}")
            });
        replayed_states.push(state.clone());
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::pipeline::{ProofGenerationConfig, ProverBackend};

    fn test_config(trusted_start_height: Option<u32>) -> ProofGenerationConfig {
        ProofGenerationConfig {
            prev_proof_path: None,
            trusted_start_height,
            num_headers: 1,
            batch_count: 1,
            db_path: concat!(env!("CARGO_MANIFEST_DIR"), "/../../headers.db").into(),
            output_dir: ".".into(),
            generate_groth16: false,
            execute_only: true,
            prover_backend: ProverBackend::Mock,
            cuda_device_id: None,
        }
    }

    fn open_test_db() -> DbConn {
        let config = test_config(None);
        crate::util::DbConfig::new(&config.db_path)
            .connect()
            .expect("failed to open test database")
    }

    #[test]
    fn prepare_batch_starts_at_genesis_without_resume_cursor() {
        let genesis_hash = crate::pipeline::input::parse_genesis_hash().unwrap();
        let db = open_test_db();
        let config = test_config(None);
        let batch = prepare_batch(
            config.prev_proof_path.as_ref(),
            config.trusted_start_height,
            config.num_headers,
            &db,
            genesis_hash,
        )
        .unwrap();

        assert_eq!(batch.first_new_height, 1);
        assert_eq!(batch.end_height, 1);
    }

    #[test]
    fn prepare_batch_uses_trusted_start_height_as_resume_cursor() {
        let genesis_hash = crate::pipeline::input::parse_genesis_hash().unwrap();
        let db = open_test_db();
        let config = test_config(Some(2016));
        let batch = prepare_batch(
            config.prev_proof_path.as_ref(),
            config.trusted_start_height,
            config.num_headers,
            &db,
            genesis_hash,
        )
        .unwrap();

        assert_eq!(batch.first_new_height, 2017);
        assert_eq!(batch.end_height, 2017);
    }
}

