1	//! Logic for parsing the public prover input and constructing the `Input` struct.
2	
3	use alloc::vec::Vec;
4	
5	use crate::{
6	    check_exact_len, copy_from_bytes, copy_to_bytes, cycle_track, slice_from_bytes, BlockTimestamp,
7	    NewHeader, ParseError, PublicChainClaim, PublicValuesDigest, VerifierKeyDigest,
8	    NEW_HEADER_SIZE, PUBLIC_CHAIN_CLAIM_SIZE, RECURSIVE_PROOF_SIZE,
9	};
10	
11	// ============================================================================
12	// Input & InputError
13	// ============================================================================
14	
15	/// Complete typed public prover input.
16	///
17	/// The full validation state is supplied separately as private witness data.
18	/// Its public preimage fields must match [`claim`](Self::claim) before the
19	/// guest uses it to validate headers.
20	#[derive(Debug, Clone, PartialEq, Eq)]
21	pub struct Input {
22	    pub claim: PublicChainClaim,
23	    pub recursive_proof: RecursiveProof,
24	}
25	
26	/// Recursive proof metadata that authenticates the current [`State`](crate::State).
27	///
28	/// `previous_return_code` must be 0 (success) for the guest to accept the
29	/// recursive continuation.  A nonzero value means the prior proof committed a
30	/// validation failure, and extending from it is rejected.
31	#[repr(C)]
32	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
33	pub struct RecursiveProof {
34	    pub verifier_key: VerifierKeyDigest,
35	    pub public_values_digest: PublicValuesDigest,
36	    /// Return code from the previous proof (0 = success, nonzero = failure).
37	    pub previous_return_code: u8,
38	    /// Padding to maintain 4-byte alignment.
39	    pub _pad: [u8; 3],
40	}
41	
42	impl Default for RecursiveProof {
43	    fn default() -> Self {
44	        Self {
45	            verifier_key: VerifierKeyDigest::from_raw([0u32; 8]),
46	            public_values_digest: PublicValuesDigest::from_raw([0u8; 32]),
47	            previous_return_code: 0,
48	            _pad: [0u8; 3],
49	        }
50	    }
51	}
52	
53	/// Parse and validation errors for [`Input`].
54	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
55	pub enum InputError {
56	    #[error("input parse error: {0}")]
57	    Parse(ParseError),
58	}
59	
60	/// Parse and validation errors for the new-header private witness batch.
61	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
62	pub enum NewHeaderHintError {
63	    #[error("new-header hint payload length mismatch: expected {expected} bytes, got {actual}")]
64	    PayloadLengthInvalid { expected: usize, actual: usize },
65	    #[error("new-header hint parse error: {0}")]
66	    Parse(ParseError),
67	}
68	
69	/// Parse and validation errors for median-time-past private witness hints.
70	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
71	pub enum MedianTimePastHintError {
72	    #[error("median hint payload length mismatch: expected {expected} bytes, got {actual}")]
73	    PayloadLengthInvalid { expected: usize, actual: usize },
74	    #[error("median hint parse error: {0}")]
75	    Parse(ParseError),
76	}
77	
78	impl From<ParseError> for InputError {
79	    fn from(value: ParseError) -> Self {
80	        Self::Parse(value)
81	    }
82	}
83	
84	impl RecursiveProof {
85	    /// Parse and validate a RecursiveProof from exactly [`RECURSIVE_PROOF_SIZE`] bytes.
86	    pub fn parse(bytes: &[u8]) -> Result<Self, InputError> {
87	        cycle_track("input/recursive_proof", || {
88	            copy_from_bytes(bytes).map_err(InputError::from)
89	        })
90	    }
91	
92	    /// Serialize to exactly [`RECURSIVE_PROOF_SIZE`] bytes.
93	    #[must_use]
94	    pub fn to_bytes(&self) -> [u8; RECURSIVE_PROOF_SIZE] {
95	        copy_to_bytes(self)
96	    }
97	}
98	
99	/// Serialize new headers.
100	#[must_use]
101	pub fn serialize_new_headers(headers: &[NewHeader]) -> Vec<u8> {
