186	/// Parse errors for fixed-width serialized core types.
187	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
188	pub enum ParseError {
189	    #[error("invalid length: expected {expected}, got {actual}")]
190	    InvalidLength { expected: usize, actual: usize },
191	    #[error("misaligned input requires {required}-byte alignment")]
192	    Misaligned { required: usize },
193	    #[error("truncated input at offset {offset}: need {needed} bytes, got {actual}")]
194	    Truncated {
195	        offset: usize,
196	        needed: usize,
197	        actual: usize,
198	    },
199	}
