503	/// Wire layout of the minimal public values committed by the prover.
504	///
505	/// Layout (169 bytes, little-endian):
506	/// ```text
507	///  0.. 32  genesis_hash        [u8; 32]
508	/// 32.. 64  tip_hash            [u8; 32]
509	/// 64.. 96  chain_work          [u8; 32]  (u256 LE)
510	/// 96..100  height              u32 LE
511	/// 100      return_code         u8  (0 = success, nonzero = failure)
512	/// 101..105 failure_height      u32 LE  (0 on success)
513	/// 105..137 continuation_digest [u8; 32]
514	/// 137..169 verifier_key         [u8; 32]  ([u32; 8] LE words)
515	/// ```
516	///
517	/// Serialized manually to avoid struct padding; use [`MinimalPublicValues::to_bytes`]
518	/// and [`MinimalPublicValues::parse`] rather than transmuting.
519	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
520	pub struct MinimalPublicValues {
521	    pub genesis_hash: BlockHash,
522	    pub tip_hash: BlockHash,
523	    pub chain_work: [u8; 32],
524	    pub height: u32,
525	    pub return_code: u8,
526	    pub failure_height: u32,
527	    pub continuation_digest: [u8; 32],
528	    pub verifier_key: VerifierKeyDigest,
529	}
530	
531	/// Size of the serialized [`MinimalPublicValues`] in bytes.
532	pub const MINIMAL_PV_SIZE: usize = 32 + 32 + 32 + 4 + 1 + 4 + 32 + 32; // = 169
533	
534	impl MinimalPublicValues {
535	    /// Build success public values from a public claim and continuation digest.
536	    #[must_use]
537	    pub fn success(
538	        claim: &PublicChainClaim,
539	        continuation_digest: [u8; 32],
540	        verifier_key: VerifierKeyDigest,
541	    ) -> Self {
542	        Self {
543	            genesis_hash: claim.genesis_hash,
544	            tip_hash: claim.tip_hash,
545	            chain_work: claim.chain_work.to_le_bytes(),
546	            height: claim.height,
547	            return_code: 0,
548	            failure_height: 0,
549	            continuation_digest,
550	            verifier_key,
551	        }
552	    }
553	
554	    /// Build failure public values from a public claim, error, and continuation digest.
555	    #[must_use]
556	    pub fn failure(
557	        claim: &PublicChainClaim,
558	        error_code: ValidationErrorCode,
559	        failure_height: u32,
560	        continuation_digest: [u8; 32],
561	        verifier_key: VerifierKeyDigest,
562	    ) -> Self {
563	        Self {
564	            genesis_hash: claim.genesis_hash,
565	            tip_hash: claim.tip_hash,
566	            chain_work: claim.chain_work.to_le_bytes(),
567	            height: claim.height,
568	            return_code: error_code.as_byte(),
569	            failure_height,
570	            continuation_digest,
571	            verifier_key,
572	        }
573	    }
574	
575	    /// Serialize to exactly [`MINIMAL_PV_SIZE`] bytes (no padding).
576	    #[must_use]
577	    pub fn to_bytes(&self) -> [u8; MINIMAL_PV_SIZE] {
578	        let mut out = [0u8; MINIMAL_PV_SIZE];
579	        out[0..32].copy_from_slice(self.genesis_hash.to_le_bytes_slice());
580	        out[32..64].copy_from_slice(self.tip_hash.to_le_bytes_slice());
581	        out[64..96].copy_from_slice(&self.chain_work);
582	        out[96..100].copy_from_slice(&self.height.to_le_bytes());
583	        out[100] = self.return_code;
584	        out[101..105].copy_from_slice(&self.failure_height.to_le_bytes());
585	        out[105..137].copy_from_slice(&self.continuation_digest);
586	        out[137..169].copy_from_slice(&self.verifier_key.to_bytes());
587	        out
588	    }
589	
590	    /// Deserialize from exactly [`MINIMAL_PV_SIZE`] bytes.
591	    pub fn parse(bytes: &[u8]) -> Result<Self, PublicValuesParseError> {
592	        if bytes.len() != MINIMAL_PV_SIZE {
593	            return Err(PublicValuesParseError::InvalidLength {
594	                actual: bytes.len(),
595	            });
596	        }
597	        let genesis_hash = BlockHash::new(bytes[0..32].try_into().unwrap());
598	        let tip_hash = BlockHash::new(bytes[32..64].try_into().unwrap());
599	        let chain_work: [u8; 32] = bytes[64..96].try_into().unwrap();
600	        let height = u32::from_le_bytes(bytes[96..100].try_into().unwrap());
601	        let return_code = bytes[100];
602	        let failure_height = u32::from_le_bytes(bytes[101..105].try_into().unwrap());
603	        let continuation_digest: [u8; 32] = bytes[105..137].try_into().unwrap();
604	        let verifier_key = VerifierKeyDigest::from_bytes(bytes[137..169].try_into().unwrap());
605	        Ok(Self {
606	            genesis_hash,
607	            tip_hash,
608	            chain_work,
609	            height,
610	            return_code,
611	            failure_height,
612	            continuation_digest,
613	            verifier_key,
614	        })
615	    }
616	
617	    /// Extract the chain work as a [`ChainWork`].
618	    #[must_use]
619	    pub fn chain_work(&self) -> ChainWork {
620	        ChainWork::from_le_bytes(self.chain_work)
621	    }
622	
623	    /// Return the error code if this is a failure, or `None` on success.
624	    pub fn error_code(&self) -> Option<Result<ValidationErrorCode, PublicValuesParseError>> {
625	        if self.return_code == 0 {
626	            None
627	        } else {
628	            Some(ValidationErrorCode::try_from(self.return_code))
629	        }
630	    }
631	}
