851	/// Subtract `rhs` from `self` in place. Returns `true` if there was an underflow (borrow out).
852	#[must_use]
853	fn sub_assign(lhs: &mut u256, rhs: u256) -> bool {
854	    let mut borrow = false;
855	
856	    let lhs_limbs: &mut [u64; 4] = lhs.as_limbs_mut();
857	    let rhs_limbs = rhs.as_limbs();
858	
859	    let (a, b1) = lhs_limbs[0].overflowing_sub(rhs_limbs[0]);
860	    let (a, b2) = a.overflowing_sub(borrow as u64);
861	    lhs_limbs[0] = a;
862	    borrow = b1 || b2;
863	
864	    let (a, b1) = lhs_limbs[1].overflowing_sub(rhs_limbs[1]);
865	    let (a, b2) = a.overflowing_sub(borrow as u64);
866	    lhs_limbs[1] = a;
867	    borrow = b1 || b2;
868	
869	    let (a, b1) = lhs_limbs[2].overflowing_sub(rhs_limbs[2]);
870	    let (a, b2) = a.overflowing_sub(borrow as u64);
871	    lhs_limbs[2] = a;
872	    borrow = b1 || b2;
873	
874	    let (a, b1) = lhs_limbs[3].overflowing_sub(rhs_limbs[3]);
875	    let (a, b2) = a.overflowing_sub(borrow as u64);
876	    lhs_limbs[3] = a;
877	    borrow = b1 || b2;
878	
879	    borrow
880	}
