914	/// Shift `value` left by one bit in place, returning the carry (the evicted MSB).
915	#[must_use]
916	fn shl1_with_carry(value: &mut u256) -> bool {
917	    cycle_track("pow/work/shl1_with_carry", || {
918	        let limbs = value.as_limbs_mut();
919	        let mut carry = 0u64;
920	        for limb in limbs.iter_mut() {
921	            let next_carry = *limb >> 63;
922	            *limb = (*limb << 1) | carry;
923	            carry = next_carry;
924	        }
925	        carry > 0
926	    })
927	}
