929	/// Compute one-block cumulative-work units from the expanded target.
930	///
931	/// Uses non-restoring binary long division to compute `floor(2^256 / (target + 1))`.
932	/// The loop processes 257 bits (indices 256 down to 0): at `bit == 256` we introduce
933	/// the implicit leading 1 of the dividend `2^256`; for `bit < 256` we set the
934	/// corresponding quotient bit when the remainder meets the divisor.
935	pub fn work_from_target(target: Target) -> Result<ChainWork, TargetError> {
936	    cycle_track("pow/work_from_target", || {
937	        let mut divisor = *target.as_inner();
938	        increment_target(&mut divisor)?;
939	
940	        let mut remainder = u256::from_limbs([0u64; 4]);
941	        let mut quotient = [0u64; 4];
942	        for bit in (0..=256u32).rev() {
943	            // Shift remainder left, absorbing the next dividend bit.
944	            // At bit == 256 the dividend is 2^256, so its MSB is 1; all lower bits are 0.
945	            let carry = shl1_with_carry(&mut remainder);
946	            if bit == 256 {
947	                // Inject the implicit leading 1 of 2^256 into the LSB of the shifted remainder.
948	                remainder.as_limbs_mut()[0] |= 1;
949	            }
950	            // If carry is set the remainder is effectively > 2^256, which is always >= divisor.
951	
952	            if carry || remainder >= divisor {
953	                let _ = sub_assign(&mut remainder, divisor);
954	                if bit < 256 {
955	                    quotient[(bit / 64) as usize] |= 1u64 << (bit % 64);
956	                }
957	            }
958	        }
959	
960	        Ok(ChainWork::from_limbs(quotient))
961	    })
962	}
