4	use crate::{
5	    calculate_next_target_required, check_proof_of_work, copy_from_bytes, copy_to_bytes,
6	    work_from_target, ApplyFailure, BlockHash, BlockTimestamp, ChainWork,
7	    CompactTarget, Header, NewHeader, ParseError, PrivateContinuationState, PublicChainClaim,
8	    Target, TargetError, ValidationErrorCode, EPOCH_LENGTH, PRIVATE_CONTINUATION_STATE_SIZE,
9	    STATE_SIZE, WINDOW_SIZE,
10	};
11	
12	#[cfg(all(target_os = "zkvm", feature = "profiling"))]
13	#[inline(always)]
14	pub fn cycle_track<T, F>(label: &'static str, f: F) -> T
15	where
16	    F: FnOnce() -> T,
17	{
18	    sp1_zkvm::io::write(
19	        1,
20	        alloc::format!("cycle-tracker-report-start: {label}\n").as_bytes(),
21	    );
22	    let output = f();
23	    sp1_zkvm::io::write(
24	        1,
25	        alloc::format!("cycle-tracker-report-end: {label}\n").as_bytes(),
26	    );
27	    output
28	}
29	
30	#[cfg(not(all(target_os = "zkvm", feature = "profiling")))]
31	#[inline(always)]
32	pub fn cycle_track<T, F>(_label: &'static str, f: F) -> T
33	where
34	    F: FnOnce() -> T,
35	{
36	    f()
37	}
38	
39	/// Complete authenticated validation state, serialized between recursive iterations.
40	#[repr(C)]
41	#[derive(Debug, Clone, PartialEq, Eq)]
42	pub struct State {
43	    pub header: Header,
44	    pub block_hash: BlockHash,
45	    pub genesis_hash: BlockHash,
46	    pub current_nbits: CompactTarget,
47	    pub height: u32,
48	    pub chain_work: ChainWork,
49	    pub current_work: ChainWork,
50	    /// Expanded 256-bit target for the current difficulty period.
51	    /// Cached to avoid recomputing from `current_nbits` on every block.
52	    /// Updated only at retarget boundaries and at genesis.
53	    pub current_target: Target,
54	    pub epoch_start_timestamp: BlockTimestamp,
55	    pub timestamps: [BlockTimestamp; WINDOW_SIZE],
56	}
57	
58	impl State {
59	    /// The number of timestamps currently tracked for median-time-past.
60	    #[must_use]
61	    pub fn timestamp_count(&self) -> usize {
62	        (self.height as usize + 1).min(WINDOW_SIZE)
63	    }
64	
65	    /// The circular-buffer slot containing the current tip timestamp.
66	    #[must_use]
67	    fn current_timestamp_slot(&self) -> usize {
68	        self.height as usize % WINDOW_SIZE
69	    }
70	
71	    /// Serialize to exactly [`STATE_SIZE`] bytes.
72	    #[must_use]
73	    pub fn to_bytes(&self) -> [u8; STATE_SIZE] {
74	        copy_to_bytes(self)
75	    }
76	
77	    /// Deserialize from exactly [`STATE_SIZE`] bytes.
78	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
79	        cycle_track("parse/state", || copy_from_bytes(bytes))
80	    }
81	
82	    /// Extract the verifier-visible public claim from this state.
83	    #[must_use]
84	    pub fn public_claim(&self) -> PublicChainClaim {
85	        PublicChainClaim {
86	            genesis_hash: self.genesis_hash,
87	            tip_hash: self.block_hash,
88	            chain_work: self.chain_work,
89	            height: self.height,
90	        }
91	    }
92	
93	    /// Serialize the private continuation fields directly to bytes.
94	    #[must_use]
95	    pub fn continuation_bytes(&self) -> [u8; PRIVATE_CONTINUATION_STATE_SIZE] {
96	        PrivateContinuationState::from_state(self).to_bytes()
97	    }
98	
99	    /// Compute the difficulty values that become active at a new epoch boundary.
100	    fn prepare_new_epoch(
101	        &self,
102	        previous_timestamp: BlockTimestamp,
103	    ) -> Result<(CompactTarget, Target, ChainWork), TargetError> {
104	        cycle_track("state/prepare_new_epoch", || {
105	            let (current_nbits, current_target) = calculate_next_target_required(
106	                self.current_target,
107	                self.epoch_start_timestamp,
108	                previous_timestamp,
109	            );
110	            let current_work = work_from_target(current_target)?;
111	            Ok((current_nbits, current_target, current_work))
112	        })
113	    }
114	
115	    #[must_use]
116	    fn median_time_past_hinted(&self, claimed_median: BlockTimestamp) -> bool {
117	        cycle_track("state/median_time_past_hinted", || {
118	            let window_len = self.timestamp_count();
119	            if window_len == 0 {
120	                return true;
121	            }
122	
123	            let median_index = window_len / 2;
124	
125	            let (less_count, equal_count, greater_count) =
126	                cycle_track("state/median_time_past_hinted/loop", || {
127	                    let mut less_count = 0usize;
128	                    let mut equal_count = 0usize;
129	                    let mut greater_count = 0usize;
130	                    for timestamp in self.timestamps.iter().take(window_len) {
131	                        if *timestamp < claimed_median {
132	                            less_count += 1;
133	                        } else if *timestamp > claimed_median {
134	                            greater_count += 1;
135	                        } else {
136	                            equal_count += 1;
137	                        }
138	                    }
139	                    (less_count, equal_count, greater_count)
140	                });
141	
142	            cycle_track("state/median_time_past_hinted/check_counts", || {
143	                less_count + equal_count + greater_count == window_len
144	                    && less_count <= median_index
145	                    && less_count + equal_count > median_index
146	            })
147	        })
148	    }
149	
150	    fn apply_chain_work_run(&mut self, run_work: ChainWork, run_count: u32) {
151	        if run_count > 0 {
152	            cycle_track("state/apply_headers/chain_work_flush", || {
153	                let accumulated_work = run_work * run_count;
154	                self.chain_work = self.chain_work + accumulated_work;
155	            });
156	        }
157	    }
158	
159	    #[allow(clippy::result_large_err)]
160	    pub fn apply_headers<F>(
161	        &mut self,
162	        headers: &[NewHeader],
163	        median_hints: &[BlockTimestamp],
164	        mut hash_header: F,
165	    ) -> Result<(), ApplyFailure>
166	    where
167	        F: FnMut(&Header) -> BlockHash,
168	    {
169	        cycle_track("state/apply_headers", || {
170	            assert_eq!(
171	                headers.len(),
172	                median_hints.len(),
173	                "median hint count must match header count"
174	            );
175	
176	            let mut pending_run_work: Option<ChainWork> = None;
177	            let mut pending_run_count: u32 = 0;
178	
179	            let flush_pending_chain_work =
180	                |state: &mut State, run_work: &mut Option<ChainWork>, run_count: &mut u32| {
181	                    if let Some(run_work) = run_work.take() {
182	                        state.apply_chain_work_run(run_work, *run_count);
183	                    }
184	                    *run_count = 0;
185	                };
186	
187	            for (header_index, (new_header, claimed_median)) in headers
188	                .iter()
189	                .copied()
190	                .zip(median_hints.iter().copied())
191	                .enumerate()
192	            {
193	                let candidate_height =
194	                    cycle_track("state/apply_headers/candidate_height", || self.height + 1);
195	                let previous_timestamp =
196	                    cycle_track("state/apply_headers/load_previous_timestamp", || {
197	                        self.timestamps[self.current_timestamp_slot()]
198	                    });
199	                let timestamp_slot = candidate_height as usize % WINDOW_SIZE;
200	
201	                cycle_track("state/apply_headers/median_hint_check", || {
202	                    assert!(
203	                        self.median_time_past_hinted(claimed_median),
204	                        "invalid median time past hint at header index {}",
205	                        header_index
206	                    );
207	                });
208	
209	                if cycle_track("state/apply_headers/validate/median_time_past", || {
210	                    new_header.timestamp <= claimed_median
211	                }) {
212	                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
213	                    return Err(ApplyFailure {
214	                        last_valid_state: self.clone(),
215	                        error_code: ValidationErrorCode::TimestampTooOld,
216	                        failure_height: candidate_height,
217	                    });
218	                }
219	
220	                let mut active_nbits = self.current_nbits;
221	                let mut active_target = self.current_target;
222	                let mut active_work = self.current_work;
223	                if cycle_track("state/apply_headers/check_retarget", || {
224	                    candidate_height.is_multiple_of(EPOCH_LENGTH)
225	                }) {
226	                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
227	                    let prepared = self
228	                        .prepare_new_epoch(previous_timestamp)
229	                        .expect("epoch target must not be u256::MAX — invalid blockchain data");
230	                    active_nbits = prepared.0;
231	                    active_target = prepared.1;
232	                    active_work = prepared.2;
233	                }
