240	
241	                if cycle_track("state/apply_headers/validate/pow", || {
242	                    !check_proof_of_work(block_hash, active_target)
243	                }) {
244	                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
245	                    return Err(ApplyFailure {
246	                        last_valid_state: self.clone(),
247	                        error_code: ValidationErrorCode::PowInsufficient,
248	                        failure_height: candidate_height,
249	                    });
250	                }
251	
252	                if pending_run_work != Some(active_work) {
253	                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
254	                    pending_run_work = Some(active_work);
255	                }
256	
257	                pending_run_count += 1;
258	                cycle_track("state/apply_headers/assign_state", || {
259	                    self.height = candidate_height;
260	                    self.timestamps[timestamp_slot] = header.timestamp;
261	                    self.current_nbits = active_nbits;
262	                    self.current_target = active_target;
263	                    self.current_work = active_work;
