1	//! Automated tests for error handling in the zkpow prover.
2	//!
3	//! Each test crafts specific inputs that should trigger a particular error code,
4	//! then runs the zkVM program via `client.execute()` and checks the public values.
5	//!
6	//! Input protocol:
7	//!   stdin: encoded_input(Vec<u8>) + state witness(Vec<u8>) + header witness(Vec<u8>)
8	//!          + median-time-past witness(Vec<u8>)
9	//!          → [recursive proof witness when claim.height > 0]
10	//!   output: MinimalPublicValues (169 bytes)
11	
12	use sp1_sdk::prelude::*;
13	use sp1_sdk::{Elf, HashableKey, Prover, ProverClient, SP1Stdin};
14	
15	use zkpow_host::config::db_path;
16	use zkpow_host::{observability, util};
17	
18	use zkpow_host::util::{
19	    HeaderChainPublicValues, Input, MinimalPublicValues, PublicValuesDigest, RecursiveProof,
20	    ValidationErrorCode, VerifierKeyDigest,
21	};
22	
23	const ELF: Elf = include_elf!("zkpow-guest");
24	
25	const MAINNET_GENESIS_HEX: &str =
26	    "000000000019d6689c085ae165831e934ff763ae46a2a6c172b3f1b60a8ce26f";
27	
28	/// Run the program with given inputs and return the raw public values.
29	async fn run_and_get_pv(stdin: SP1Stdin) -> Result<Vec<u8>, String> {
30	    let client = ProverClient::builder().mock().build().await;
31	    let (public_values, _report) = client
32	        .execute(ELF, stdin)
33	        .await
34	        .map_err(|e| format!("execution failed: {}", e))?;
35	    Ok(public_values.to_vec())
36	}
37	
38	fn expect_success(pv: &[u8]) -> Result<util::PublicChainClaim, String> {
39	    let parsed =
40	        HeaderChainPublicValues::parse(pv).map_err(|err| format!("failed to parse PV: {err}"))?;
41	    match parsed {
42	        HeaderChainPublicValues::Success { claim, .. } => Ok(claim),
43	        HeaderChainPublicValues::Failure { failure, .. } => Err(format!(
44	            "expected success, got error {} at height {}",
45	            failure.error_code, failure.failure_height,
46	        )),
47	    }
48	}
49	
50	fn expect_failure(
51	    pv: &[u8],
52	    expected_code: ValidationErrorCode,
53	    expected_failure_height: u32,
54	) -> Result<(), String> {
55	    let parsed =
56	        HeaderChainPublicValues::parse(pv).map_err(|err| format!("failed to parse PV: {err}"))?;
57	
58	    match parsed {
59	        HeaderChainPublicValues::Success { claim, .. } => Err(format!(
60	            "expected error {}, got success at height {}",
61	            expected_code, claim.height,
62	        )),
63	        HeaderChainPublicValues::Failure { failure, .. } => {
64	            if failure.error_code != expected_code {
65	                return Err(format!(
66	                    "expected error {}, got {}",
67	                    expected_code, failure.error_code,
68	                ));
69	            }
70	            if failure.failure_height != expected_failure_height {
71	                return Err(format!(
72	                    "expected failure height {}, got {}",
73	                    expected_failure_height, failure.failure_height,
