204	async fn test_retarget_boundary_schedule() -> Result<(), String> {
205	    const FIRST_BOUNDARY_TIP_HEIGHT: usize = 2015;
206	    const RETARGET_HEIGHT: usize = 32256;
207	    const RETARGET_TIP_HEIGHT: usize = RETARGET_HEIGHT - 1;
208	    const EPOCH_LENGTH: usize = zkpow_core::EPOCH_LENGTH as usize;
209	    let db = open_db();
210	    let genesis_state = mainnet_genesis_state();
211	
212	    let witness_first_epoch = db.load_header_batch_witness(1, FIRST_BOUNDARY_TIP_HEIGHT as u64);
213	    let first_epoch_state = util::compute_final_state_with_hints(
214	        &genesis_state,
215	        &witness_first_epoch.headers,
216	        &witness_first_epoch.median_time_past_hints,
217	    );
218	    println!(
219	        "retarget-debug: first_epoch loaded={} state.height={} state.current_nbits={:#x}",
220	        witness_first_epoch.headers.len(),
221	        first_epoch_state.height,
222	        consensus_bits(first_epoch_state.current_nbits),
223	    );
224	    let first_retarget_bits = db
225	        .load_compact_target((FIRST_BOUNDARY_TIP_HEIGHT + 1) as u64)
226	        .into_inner();
227	    if consensus_bits(first_epoch_state.current_nbits) != first_retarget_bits {
228	        return Err(format!(
229	            "expected first retarget boundary bits {:#x}, got {:#x}",
230	            first_retarget_bits,
231	            consensus_bits(first_epoch_state.current_nbits),
232	        ));
233	    }
234	
235	    let witness_retarget = db.load_header_batch_witness(1, RETARGET_TIP_HEIGHT as u64);
236	    let state = util::compute_final_state_with_hints(
237	        &genesis_state,
238	        &witness_retarget.headers,
239	        &witness_retarget.median_time_past_hints,
240	    );
241	    println!(
242	        "retarget-debug: retarget loaded={} state.height={} state.current_nbits={:#x}",
243	        witness_retarget.headers.len(),
244	        state.height,
245	        consensus_bits(state.current_nbits),
246	    );
247	
248	    let previous_epoch_bits = db
249	        .load_compact_target(RETARGET_TIP_HEIGHT as u64)
250	        .into_inner();
251	    let next_header_bits = db.load_compact_target(RETARGET_HEIGHT as u64).into_inner();
252	
253	    println!(
254	        "retarget-debug: prev_epoch_bits={:#x} next_header_bits={:#x}",
255	        previous_epoch_bits, next_header_bits,
256	    );
257	
258	    if state.height != RETARGET_TIP_HEIGHT as u32 {
259	        return Err(format!(
260	            "expected validated height {}, got {}",
261	            RETARGET_TIP_HEIGHT, state.height,
262	        ));
263	    }
264	
265	    if previous_epoch_bits == next_header_bits {
266	        return Err(format!(
267	            "expected a real retarget boundary at height {}, but bits stayed at {:#x}",
268	            RETARGET_HEIGHT, next_header_bits,
269	        ));
270	    }
271	
272	    if consensus_bits(state.current_nbits) != previous_epoch_bits {
273	        return Err(format!(
274	            "expected current epoch bits {:#x} before boundary block, got {:#x}",
275	            previous_epoch_bits,
276	            consensus_bits(state.current_nbits),
277	        ));
278	    }
279	
280	    let witness_boundary = db.load_header_batch_witness(RETARGET_HEIGHT as u64, 1);
281	    let boundary_state = util::compute_final_state_with_hints(
282	        &state,
283	        &witness_boundary.headers,
284	        &witness_boundary.median_time_past_hints,
285	    );
286	    if boundary_state.height != RETARGET_HEIGHT as u32 {
287	        return Err(format!(
288	            "expected boundary height {}, got {}",
289	            RETARGET_HEIGHT, boundary_state.height,
290	        ));
291	    }
292	    if consensus_bits(boundary_state.current_nbits) != next_header_bits {
293	        return Err(format!(
294	            "expected boundary bits {:#x}, got {:#x}",
295	            next_header_bits,
296	            consensus_bits(boundary_state.current_nbits),
297	        ));
298	    }
299	
300	    let witness_pre_boundary = db.load_header_batch_witness(1, (RETARGET_HEIGHT - 2) as u64);
301	    let pre_boundary_state = util::compute_final_state_with_hints(
302	        &genesis_state,
303	        &witness_pre_boundary.headers,
304	        &witness_pre_boundary.median_time_past_hints,
305	    );
306	
307	    if consensus_bits(pre_boundary_state.current_nbits) != previous_epoch_bits {
308	        return Err(format!(
309	            "expected pre-boundary bits {:#x}, got {:#x}",
310	            previous_epoch_bits,
311	            consensus_bits(pre_boundary_state.current_nbits),
312	        ));
313	    }
314	
315	    if (pre_boundary_state.height as usize).is_multiple_of(EPOCH_LENGTH) {
316	        return Err("pre-boundary state unexpectedly ended on an epoch boundary".to_string());
317	    }
318	
319	    Ok(())
320	}
