use sp1_sdk::prelude::*;
use sp1_sdk::SP1Proof;
use std::collections::HashMap;
use std::env::VarError;
use std::path::PathBuf;

use crate::config::db_path;
use crate::pipeline::{BoxError, ProofGenerationConfig, ProverBackend};
use crate::util;
use crate::util::{Proof, ProofCarryingState, PublicValuesDigest, VerifierKeyDigest};

const GENESIS_HASH_HEX: &str = "000000000019d6689c085ae165831e934ff763ae46a2a6c172b3f1b60a8ce26f";

pub const ENV_ZKPOW_BATCH_SIZE: &str = "ZKPOW_BATCH_SIZE";
pub const ENV_ZKPOW_BATCH_COUNT: &str = "ZKPOW_BATCH_COUNT";
pub const ENV_ZKPOW_OUTPUT_DIR: &str = "ZKPOW_OUTPUT_DIR";
pub const ENV_ZKPOW_DB_PATH: &str = "ZKPOW_DB_PATH";
pub const ENV_ZKPOW_PREV_PROOF: &str = "ZKPOW_PREV_PROOF";
pub const ENV_ZKPOW_SHOW_COMPRESSED_PROOF_SPANS: &str = "ZKPOW_SHOW_COMPRESSED_PROOF_SPANS";

pub const ENV_ZKPOW_EXECUTE_ONLY: &str = "ZKPOW_EXECUTE_ONLY";
pub const ENV_ZKPOW_GENERATE_GROTH16: &str = "ZKPOW_GENERATE_GROTH16";

pub const ENV_ZKPOW_USE_CUDA: &str = "ZKPOW_USE_CUDA";
pub const ENV_ZKPOW_CUDA_DEVICE_ID: &str = "ZKPOW_CUDA_DEVICE_ID";

const DEFAULT_BATCH_SIZE: u32 = 2016;
const DEFAULT_BATCH_COUNT: u32 = 500;

pub(crate) trait EnvSource {
    fn get(&self, var_name: &str) -> Result<String, VarError>;
}

#[derive(Debug, Clone, Copy)]
pub struct ProcessEnv;

impl EnvSource for ProcessEnv {
    fn get(&self, var_name: &str) -> Result<String, VarError> {
        std::env::var(var_name)
    }
}

#[derive(Debug, Clone, Default)]
pub struct MapEnvSource {
    values: HashMap<String, String>,
}

impl MapEnvSource {
    pub fn new(values: HashMap<String, String>) -> Self {
        Self { values }
    }
}

impl EnvSource for MapEnvSource {
    fn get(&self, var_name: &str) -> Result<String, VarError> {
        self.values
            .get(var_name)
            .cloned()
            .ok_or(VarError::NotPresent)
    }
}

pub fn parse_genesis_hash() -> Result<util::BlockHash, BoxError> {
    let mut genesis_hash: [u8; 32] = hex::decode(GENESIS_HASH_HEX)
        .map_err(|err| format!("invalid genesis hash hex: {}", err))?
        .try_into()
        .map_err(|_| "genesis hash should be 32 bytes")?;
    genesis_hash.reverse();
    Ok(util::BlockHash::new(genesis_hash))
}

pub(crate) fn parse_bool_env(
    source: &impl EnvSource,
    var_name: &'static str,
) -> Result<bool, BoxError> {
    parse_bool_env_or(source, var_name, false)
}

pub(crate) fn parse_bool_env_or(
    source: &impl EnvSource,
    var_name: &'static str,
    default: bool,
) -> Result<bool, BoxError> {
    match source.get(var_name) {
        Ok(value) => match value.to_ascii_lowercase().as_str() {
            "1" | "true" | "yes" | "on" => Ok(true),
            "0" | "false" | "no" | "off" => Ok(false),
            _ => Err(format!(
                "invalid {var_name} value `{value}`; expected one of 1,true,yes,on,0,false,no,off"
            )
            .into()),
        },
        Err(VarError::NotPresent) => Ok(default),
        Err(err) => Err(err.into()),
    }
}

pub(crate) fn parse_u32_env(
    source: &impl EnvSource,
    var_name: &'static str,
) -> Result<Option<u32>, BoxError> {
    match source.get(var_name) {
        Ok(value) => {
            Ok(Some(value.parse().map_err(|err| {
                format!("invalid {var_name} value `{value}`: {err}")
            })?))
        }
        Err(VarError::NotPresent) => Ok(None),
        Err(err) => Err(err.into()),
    }
}

fn parse_u32_env_or(
    source: &impl EnvSource,
    var_name: &'static str,
    default: u32,
) -> Result<u32, BoxError> {
    Ok(parse_u32_env(source, var_name)?.unwrap_or(default))
}

fn parse_path_env<E: EnvSource>(source: &E, var_name: &'static str) -> Option<PathBuf> {
    source.get(var_name).ok().map(PathBuf::from)
}

pub(crate) fn ensure_cuda_requested_configuration(
    use_cuda: bool,
    cuda_device_id: Option<u32>,
) -> Result<ProverBackend, BoxError> {
    if !use_cuda {
        if cuda_device_id.is_some() {
            return Err(format!(
                "{ENV_ZKPOW_CUDA_DEVICE_ID} is only valid when {ENV_ZKPOW_USE_CUDA}=1"
            )
            .into());
        }
        return Ok(ProverBackend::Cpu);
    }

    #[cfg(feature = "CUDA")]
    {
        return Ok(ProverBackend::Cuda);
    }

    #[cfg(not(feature = "CUDA"))]
    let _ = cuda_device_id;
    #[cfg(not(feature = "CUDA"))]
    Err(
        format!("{ENV_ZKPOW_USE_CUDA}=1 requires building zkpow-host with `--features CUDA`")
            .into(),
    )
}

pub(crate) fn config_from_source(
    source: &impl EnvSource,
) -> Result<ProofGenerationConfig, BoxError> {
    let use_cuda = parse_bool_env(source, ENV_ZKPOW_USE_CUDA)?;
    let cuda_device_id = parse_u32_env(source, ENV_ZKPOW_CUDA_DEVICE_ID)?;

    let execute_only = parse_bool_env(source, ENV_ZKPOW_EXECUTE_ONLY)?;
    let generate_groth16 = parse_bool_env(source, ENV_ZKPOW_GENERATE_GROTH16)?;
    if execute_only && generate_groth16 {
        return Err(format!(
            "{ENV_ZKPOW_GENERATE_GROTH16} cannot be enabled when {ENV_ZKPOW_EXECUTE_ONLY}=1"
        )
        .into());
    }

    let num_headers = parse_u32_env_or(source, ENV_ZKPOW_BATCH_SIZE, DEFAULT_BATCH_SIZE)?;
    let batch_count = parse_u32_env_or(source, ENV_ZKPOW_BATCH_COUNT, DEFAULT_BATCH_COUNT)?;

    let configured_backend = ensure_cuda_requested_configuration(use_cuda, cuda_device_id)?;
    let prover_backend = if execute_only && configured_backend == ProverBackend::Cpu {
        ProverBackend::Mock
    } else {
        configured_backend
    };

    Ok(ProofGenerationConfig {
        prev_proof_path: parse_path_env(source, ENV_ZKPOW_PREV_PROOF),
        trusted_start_height: None,
        num_headers,
        batch_count,
        db_path: parse_path_env(source, ENV_ZKPOW_DB_PATH)
            .unwrap_or_else(|| PathBuf::from(db_path())),
        output_dir: parse_path_env(source, ENV_ZKPOW_OUTPUT_DIR)
            .unwrap_or_else(|| PathBuf::from(".")),
        generate_groth16,
        execute_only,
        prover_backend,
        cuda_device_id,
    })
}

pub fn config_from_env() -> Result<ProofGenerationConfig, BoxError> {
    config_from_source(&ProcessEnv)
}

pub fn build_proof(
    vk: &sp1_prover::SP1VerifyingKey,
    previous_proof: Option<&SP1ProofWithPublicValues>,
) -> Result<(VerifierKeyDigest, Proof), BoxError> {
    let verifier_key = VerifierKeyDigest::from_raw(vk.hash_u32());
    let proof = if let Some(prev_proof_val) = previous_proof {
        let pv_bytes = prev_proof_val.public_values.to_vec();
        let exit_code = match zkpow_core::HeaderChainPublicValues::parse(&pv_bytes) {
            Ok(zkpow_core::HeaderChainPublicValues::Success { .. }) => 0u8,
            Ok(zkpow_core::HeaderChainPublicValues::Failure { failure, .. }) => {
                failure.error_code.as_byte()
            }
            Err(e) => {
                return Err(format!("failed to parse previous proof public values: {}", e).into())
            }
        };
        Proof {
            public_values_digest: PublicValuesDigest::from_raw(util::compute_pv_digest(&pv_bytes)),
            exit_code,
            ..Default::default()
        }
    } else {
        Proof::default()
    };
    Ok((verifier_key, proof))
}

pub fn build_stdin(
    pcs: &ProofCarryingState,
    state: &util::State,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    previous_proof: Option<(&SP1ProofWithPublicValues, &sp1_prover::SP1VerifyingKey)>,
) -> Result<SP1Stdin, BoxError> {
    let mut stdin = SP1Stdin::new();
    stdin.write_vec(pcs.to_bytes());
    stdin.write_vec(state.to_bytes().to_vec());
    stdin.write_vec(zkpow_core::serialize_new_headers(headers));
    stdin.write_vec(zkpow_core::serialize_median_hints(median_hints));

    if let Some((prev_proof, vk)) = previous_proof {
        let SP1Proof::Compressed(inner_proof) = &prev_proof.proof else {
            return Err("previous proof is not compressed".into());
        };
        stdin.write_proof(inner_proof.as_ref().clone(), vk.vk.clone());
    }

    Ok(stdin)
}

//! Utilities for the zkpow prover script.

mod db;
mod hash;
mod simulate;

pub use zkpow_core::{
    parse_median_hints, parse_new_headers, serialize_median_hints, serialize_new_headers,
    target_from_bits, u256, work_from_target, ApplyFailure, BlockHash, BlockTimestamp, ChainWork,
    Claim, CompactTarget, ContinuationData, Header, HeaderChainPublicValues, InputError,
    MinimalPublicValues, NewHeader, NewHeaderHintError, ParseError, Proof, ProofCarryingState,
    ProofFailure, PublicValuesDigest, PublicValuesParseError, State, Target, ValidationErrorCode,
    VerifierKeyDigest, CLAIM_SIZE, CONTINUATION_DATA_SIZE, GENESIS_TARGET, MINIMAL_PV_SIZE,
    NEW_HEADER_SIZE, PROOF_SIZE, STATE_SIZE,
};

pub use db::{
    genesis_state_from_record, state_from_db_at_height, DbConfig, DbConn, HeaderBatchWitness,
    HeaderRecord,
};
pub use hash::{
    compute_pv_digest, continuation_digest, continuation_digest_from_state, hash_header, sha256d,
};
pub use simulate::{
    compute_final_state_with_hints, median_time_past_hints_from_records, records_to_new_headers,
};

#[cfg(test)]
mod tests {
    use super::*;
    use crate::config::db_path;
    use zkpow_core::{BlockTimestamp, CompactTarget, GENESIS_NBITS, GENESIS_TARGET, WINDOW_SIZE};

    fn make_pcs() -> ContinuationData {
        ContinuationData {
            current_nbits: CompactTarget::new(GENESIS_NBITS),
            current_work: ChainWork::from_limbs([1, 2, 3, 4]),
            current_target: GENESIS_TARGET,
            epoch_start_timestamp: BlockTimestamp::new(500),
            timestamps: [BlockTimestamp::new(10); WINDOW_SIZE],
        }
    }

    #[test]
    fn continuation_digest_changes_on_any_byte_mutation() {
        let pcs = make_pcs();
        let base_digest = continuation_digest(&pcs);

        let bytes = pcs.to_bytes();
        for i in 0..bytes.len() {
            let mut mutated = bytes;
            mutated[i] ^= 0xFF;
            if let Ok(pcs2) = ContinuationData::parse(&mutated) {
                let digest2 = continuation_digest(&pcs2);
                assert_ne!(
                    base_digest, digest2,
                    "digest unchanged after mutating byte {i}"
                );
            }
        }
    }

    #[test]
    fn continuation_digest_is_deterministic() {
        let pcs = make_pcs();
        assert_eq!(continuation_digest(&pcs), continuation_digest(&pcs));
    }

    fn open_db() -> DbConn {
        DbConfig::new(db_path())
            .connect()
            .expect("failed to open test database")
    }

    #[test]
    fn db_median_time_hints_match_genesis_seeded_state() {
        let db = open_db();
        let genesis = db.load_header_record(0);
        let genesis_hash = hash_header(&genesis.header);
        let genesis_state = genesis_state_from_record(genesis, genesis_hash);
        let records = db.load_header_records(1, 13);
        let headers = records_to_new_headers(&records);
        let hints = median_time_past_hints_from_records(&records);

        compute_final_state_with_hints(&genesis_state, &headers, &hints);
    }

    #[test]
    fn batch_witness_loader_matches_record_projection() {
        let db = open_db();
        let records = db.load_header_records(1, 13);
        let witness = db.load_header_batch_witness(1, 13);

        assert_eq!(witness.headers, records_to_new_headers(&records));
        assert_eq!(
            witness.median_time_past_hints,
            median_time_past_hints_from_records(&records)
        );
    }

    #[test]
    fn compute_final_state_with_hints_reaches_expected_height() {
        let db = open_db();
        let genesis = db.load_header_record(0);
        let genesis_hash = hash_header(&genesis.header);
        let genesis_state = genesis_state_from_record(genesis, genesis_hash);
        let witness = db.load_header_batch_witness(1, 128);

        let final_state = compute_final_state_with_hints(
            &genesis_state,
            &witness.headers,
            &witness.median_time_past_hints,
        );

        assert_eq!(final_state.height, 128);
    }

    #[test]
    fn applying_headers_one_at_a_time_matches_db_claims() {
        let db = open_db();
        let genesis = db.load_header_record(0);
        let genesis_hash = hash_header(&genesis.header);
        let mut state = genesis_state_from_record(genesis, genesis_hash);
        let witness = db.load_header_batch_witness(1, 64);

        for (index, (header, median_time_past)) in witness
            .headers
            .iter()
            .copied()
            .zip(witness.median_time_past_hints.iter().copied())
            .enumerate()
        {
            state
                .apply_headers(&[header], &[median_time_past], hash_header)
                .expect("header should apply");
            let height = (index as u32) + 1;
            let db_claim = db.load_public_claim(height as u64, genesis_hash);
            assert_eq!(state.public_claim(), db_claim);
        }
    }

    #[test]
    fn db_retarget_schedule_matches_height_40320() {
        let db = open_db();
        let genesis = db.load_header_record(0);
        let genesis_hash = hash_header(&genesis.header);
        let genesis_state = genesis_state_from_record(genesis, genesis_hash);
        let witness_1 = db.load_header_batch_witness(1, 40319);
        let state = compute_final_state_with_hints(
            &genesis_state,
            &witness_1.headers,
            &witness_1.median_time_past_hints,
        );
        let pre_boundary_nbits = db.load_compact_target(40319);

        assert_eq!(state.height, 40319);
        assert_eq!(state.current_nbits, pre_boundary_nbits);

        let witness_2 = db.load_header_batch_witness(40320, 1);
        let boundary_state = compute_final_state_with_hints(
            &state,
            &witness_2.headers,
            &witness_2.median_time_past_hints,
        );
        assert_eq!(boundary_state.height, 40320);
        let boundary_nbits = db.load_compact_target(40320);
        assert_eq!(boundary_state.current_nbits, boundary_nbits);
    }

    #[test]
    fn db_chainwork_matches_simulated_batches() {
        enum InitialState {
            Genesis,
            DbHeight(u32),
        }

        let cases = [
            (
                "genesis-started batch",
                InitialState::Genesis,
                1,
                4096,
                4096,
            ),
            (
                "retarget-boundary batch",
                InitialState::DbHeight(30240),
                30241,
                2016,
                32256,
            ),
        ];

        let db = open_db();
        let genesis = db.load_header_record(0);
        let genesis_hash = hash_header(&genesis.header);

        for (name, initial_state, record_start, record_count, expected_height) in cases {
            let initial_state = match initial_state {
                InitialState::Genesis => genesis_state_from_record(genesis.clone(), genesis_hash),
                InitialState::DbHeight(height) => {
                    state_from_db_at_height(&db, height, genesis_hash)
                }
            };
            let witness = db.load_header_batch_witness(record_start, record_count);
            let final_state = compute_final_state_with_hints(
                &initial_state,
                &witness.headers,
                &witness.median_time_past_hints,
            );
            let db_claim = db.load_public_claim(expected_height as u64, genesis_hash);
            let db_nbits = db.load_compact_target(expected_height as u64);

            assert_eq!(final_state.height, expected_height, "{name}: height");
            assert_eq!(final_state.public_claim(), db_claim, "{name}: claim");
            assert_eq!(final_state.current_nbits, db_nbits, "{name}: nbits");
            assert_eq!(
                final_state.chain_work, db_claim.chain_work,
                "{name}: chainwork"
            );
        }
    }
}

use sha2::{Digest, Sha256};
use sp1_sdk::SP1PublicValues;

use super::{BlockHash, ContinuationData, Header, State};

/// Compute SHA256d of the given data.
pub fn sha256d(data: &[u8]) -> [u8; 32] {
    Sha256::digest(Sha256::digest(data)).into()
}

/// Hash a full Bitcoin header with SHA256d.
#[must_use]
pub fn hash_header(header: &Header) -> BlockHash {
    BlockHash::new(sha256d(&header.to_bytes()))
}

/// Compute SHA-256 digest of public values.
pub fn compute_pv_digest(committed_bytes: &[u8]) -> [u8; 32] {
    let digest = SP1PublicValues::from(committed_bytes).hash();
    digest
        .try_into()
        .expect("SP1 public values hash must be 32 bytes")
}

/// Compute the continuation digest: SHA-256 of the serialized continuation data.
pub fn continuation_digest(data: &ContinuationData) -> [u8; 32] {
    Sha256::digest(data.to_bytes()).into()
}

/// Compute the continuation digest directly from a [`State`].
pub fn continuation_digest_from_state(state: &State) -> [u8; 32] {
    continuation_digest(&ContinuationData::from_state(state))
}

//! zkpow — Header-Construction Architecture
//!
//! Validates a batch of Bitcoin block headers incrementally.
//! The prover supplies only non-deterministic fields (version, merkle_root,
//! timestamp, nonce). The circuit constructs the full 80-byte header from
//! authenticated state, then hashes and validates.
//!
//! Input protocol:
//!   1. encoded_input: Vec<u8>  (ProofCarryingState bytes)
//!   2. state_witness: Vec<u8>  (State bytes)
//!   3. header_hints: Vec<u8>
//!   4. median_time_past_hints: Vec<u8>
//!   5. If `claim.height > 0`, recursive proof witness (via write_proof)
//!
//! Output: MinimalPublicValues (169 bytes) on success or failure.

#![no_main]
sp1_zkvm::entrypoint!(main);

use zkpow_core::{
    cycle_track, parse_median_hints, parse_new_headers, Claim, Header, MinimalPublicValues,
    Proof, ProofCarryingState, State, VerifierKeyDigest, MINIMAL_PV_SIZE,
    CONTINUATION_DATA_SIZE,
};

mod sha256;

use sha256::{sha256_116bytes, sha256_169bytes, sha256d_80bytes};

/// Hash a full 80-byte Bitcoin header with SHA256d.
fn hash_header(header: &Header) -> zkpow_core::BlockHash {
    cycle_track("crypto/hash_header", || {
        let header_bytes = header.to_bytes();
        zkpow_core::BlockHash::new(sha256d_80bytes(&header_bytes))
    })
}

/// Compute the continuation digest: SHA-256 of the serialized private continuation fields.
fn compute_continuation_digest(state: &State) -> [u8; 32] {
    cycle_track("crypto/continuation_digest", || {
        let cd_bytes: [u8; CONTINUATION_DATA_SIZE] = state.continuation_bytes();
        sha256_116bytes(&cd_bytes)
    })
}

/// Commit the minimal public values and halt.
fn commit_minimal_pv(pv: &MinimalPublicValues) -> ! {
    let bytes: [u8; MINIMAL_PV_SIZE] = pv.to_bytes();
    sp1_zkvm::io::commit_slice(&bytes);
    sp1_zkvm::syscalls::syscall_halt(0)
}

// ============================================================================
// Recursive proof verification
// ============================================================================

fn verify_recursive_proof(
    proof: &Proof,
    verifier_key: &VerifierKeyDigest,
    prior_claim: &Claim,
    prior_continuation_bytes: &[u8; CONTINUATION_DATA_SIZE],
) {
    cycle_track("recursive/verify_proof", || {
        // Reject continuation from a failed prior proof.
        if proof.exit_code != 0 {
            panic!(
                "recursive continuation rejected: prior proof has exit code {}",
                proof.exit_code
            );
        }

        // 1. Hash the supplied continuation state.
        let continuation_digest = cycle_track("recursive/continuation_digest", || {
            sha256_116bytes(prior_continuation_bytes)
        });

        // 2. Reconstruct the prior proof's minimal public values and hash them.
        let prior_pv = MinimalPublicValues::success(
            prior_claim,
            continuation_digest,
            *verifier_key,
        );
        let prior_pv_bytes: [u8; MINIMAL_PV_SIZE] = prior_pv.to_bytes();
        let actual_pv_hash = cycle_track("recursive/public_values_digest", || {
            sha256_169bytes(&prior_pv_bytes)
        });

        if actual_pv_hash != proof.public_values_digest.into_raw() {
            panic!("recursive proof public values digest mismatch");
        }

        // 3. Verify the SP1 proof.
        cycle_track("recursive/sp1_verify", || {
            sp1_zkvm::lib::verify::verify_sp1_proof(
                verifier_key.as_raw(),
                proof.public_values_digest.as_raw(),
            );
        });
    });
}

pub fn main() {
    cycle_track("main", || {
        let input_bytes = sp1_zkvm::io::read_vec();
        let state_bytes = sp1_zkvm::io::read_vec();
        let header_hint_bytes = sp1_zkvm::io::read_vec();
        let median_hint_bytes = sp1_zkvm::io::read_vec();

        let pcs = ProofCarryingState::parse(&input_bytes).expect("input should parse");
        let mut state = cycle_track("input/parse_state_witness", || {
            State::parse(&state_bytes).expect("state witness should parse")
        });
        cycle_track("input/verify_state_claim", || {
            assert!(
                state.genesis_hash == pcs.claim.genesis_hash
                    && state.block_hash == pcs.claim.tip_hash
                    && state.chain_work == pcs.claim.chain_work
                    && state.height == pcs.claim.height,
                "state witness public claim mismatch"
            );
        });
        let header_hints = cycle_track("input/parse_header_hints", || {
            parse_new_headers(&header_hint_bytes).expect("new header hints should parse")
        });
        let median_hints = cycle_track("input/parse_median_hints", || {
            parse_median_hints(&median_hint_bytes, header_hints.len())
                .expect("median time past hints should parse")
        });

        if pcs.claim.height > 0 {
            let prior_continuation_bytes: [u8; CONTINUATION_DATA_SIZE] =
                state.continuation_bytes();
            verify_recursive_proof(
                &pcs.proof,
                &pcs.verifier_key,
                &pcs.claim,
                &prior_continuation_bytes,
            );
        }

        // Apply headers; on failure commit minimal PV and halt.
        if let Err(failure) = state.apply_headers(header_hints, median_hints, hash_header) {
            let digest = compute_continuation_digest(&failure.last_valid_state);
            let pv = MinimalPublicValues::failure(
                &failure.last_valid_state.public_claim(),
                failure.error_code,
                failure.failure_height,
                digest,
                pcs.verifier_key,
            );
            commit_minimal_pv(&pv);
        }

        let digest = compute_continuation_digest(&state);
        let pv = MinimalPublicValues::success(
            &state.public_claim(),
            digest,
            pcs.verifier_key,
        );
        commit_minimal_pv(&pv);
    });
}

