1	//! SHA-256 via SP1 precompile syscalls.
2	//!
3	//! Specialized functions for the exact sizes we need:
4	//! - `sha256_80bytes`: hashes exactly 80 bytes (Bitcoin block header)
5	//! - `sha256_32bytes`: hashes exactly 32 bytes (intermediate hash output)
6	//! - `sha256_169bytes`: hashes exactly 169 bytes (minimal public values)
7	//! - `sha256_116bytes`: hashes exactly 116 bytes (private continuation state)
8	//! - `sha256d_80bytes`: hashes exactly 80 bytes with SHA256d
9	//!
10	//! No loops, no branching on block count — the padding and block layout
11	//! are hardcoded for each size.
12	
13	use sp1_zkvm::syscalls::{syscall_sha256_compress, syscall_sha256_extend};
14	
15	const SHA256_IV: [u64; 8] = [
16	    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
17	];
18	
19	/// Extract a 32-byte hash from the SHA-256 state.
20	/// The state stores 8 × u64; each contributes its low 32 bits in big-endian order.
21	#[inline]
22	fn state_to_hash(state: &[u64; 8]) -> [u8; 32] {
23	    let b0 = state[0].to_be_bytes();
24	    let b1 = state[1].to_be_bytes();
25	    let b2 = state[2].to_be_bytes();
26	    let b3 = state[3].to_be_bytes();
27	    let b4 = state[4].to_be_bytes();
28	    let b5 = state[5].to_be_bytes();
29	    let b6 = state[6].to_be_bytes();
30	    let b7 = state[7].to_be_bytes();
31	    [
32	        b0[4], b0[5], b0[6], b0[7], //
33	        b1[4], b1[5], b1[6], b1[7], //
34	        b2[4], b2[5], b2[6], b2[7], //
35	        b3[4], b3[5], b3[6], b3[7], //
36	        b4[4], b4[5], b4[6], b4[7], //
37	        b5[4], b5[5], b5[6], b5[7], //
38	        b6[4], b6[5], b6[6], b6[7], //
39	        b7[4], b7[5], b7[6], b7[7], //
40	    ]
41	}
42	
43	#[inline]
44	const fn be_u64(a: u8, b: u8, c: u8, d: u8) -> u64 {
45	    ((a as u64) << 24) | ((b as u64) << 16) | ((c as u64) << 8) | (d as u64)
46	}
47	
48	#[inline]
49	const fn be_u64_from_slice(s: &[u8], i: usize) -> u64 {
50	    let i = i * 4;
51	    ((s[i + 0] as u64) << 24)
52	        | ((s[i + 1] as u64) << 16)
53	        | ((s[i + 2] as u64) << 8)
54	        | (s[i + 3] as u64)
55	}
56	
57	macro_rules! unroll {
58	    ($n:expr, $body:block) => {
59	        //unroll!(@inner 0usize, $n, $body);
60	    };
61	
62	    (@inner $i:expr, $n:expr, $body:block) => {{
63	        const I: usize = $i;
64	        $body
65	    }
66	    if $i + 1 < $n {
67	        //unroll!(@inner $i + 1, $n, $body);
68	    }};
69	}
70	
71	// Load 16 u64 words from `data` starting at block index `block`
72	macro_rules! load_block_from_data {
73	    ($w:ident, $data:expr, $block:expr) => {
74	        unroll!(16, {
75	            let base = $block * 64 + I * 4;
76	            $w[I] = be_u64(
77	                $data[base + 0],
78	                $data[base + 1],
79	                $data[base + 2],
80	                $data[base + 3],
81	            )
82	        });
83	    };
84	}
85	
86	// Load 16 u64 words from a 64‑byte buffer
87	macro_rules! load_block_from_buf {
88	    ($w:ident, $buf:expr) => {
89	        unroll!(16, {
90	            let b = I * 4;
91	            $w[I] = be_u64($buf[b + 0], $buf[b + 1], $buf[b + 2], $buf[b + 3])
92	        });
93	    };
94	}
95	
96	// Common “load + extend + compress” shape
97	macro_rules! process_block {
98	    ($w:ident, $state:expr, $loader:expr) => {{
99	        $loader;
100	        syscall_sha256_extend(&mut $w);
101	        syscall_sha256_compress(&mut $w, $state);
102	    }};
103	}
104	
105	pub fn sha256_fixed<const N: usize>(data: &[u8; N]) -> [u8; 32] {
106	    const FULL_BLOCKS: usize = N / 64;
107	    const REM: usize = N % 64;
108	    const BITLEN: u64 = (N as u64) * 8;
109	
110	    let mut state = SHA256_IV;
111	    let mut w = [0u64; 64];
112	
113	    // ── Full 64‑byte blocks ─────────────────────────────────────────────
114	    unroll!(FULL_BLOCKS, {
115	        process_block!(w, &mut state, {
116	            load_block_from_data!(w, data, I);
117	        });
118	    });
119	
120	    // ── Final padded block(s) ───────────────────────────────────────────
121	    let mut pad = [0u8; 64];
122	
123	    // Copy remaining bytes
124	    const START: usize = FULL_BLOCKS * 64;
125	    unroll!(64, {
126	        if I < REM {
127	            pad[I] = data[START + I];
128	        }
129	    });
130	
131	    // Append 0x80
132	    pad[REM] = 0x80;
133	
134	    let bitlen_bytes = BITLEN.to_be_bytes();
135	
136	    if REM <= 55 {
137	        // Length fits in this block
138	        unroll!(8, {
139	            pad[56 + I] = bitlen_bytes[I];
140	        });
141	
142	        process_block!(w, &mut state, {
143	            load_block_from_buf!(w, pad);
144	        });
145	    } else {
146	        // Need two final blocks
147	
148	        // First padded block
149	        process_block!(w, &mut state, {
150	            load_block_from_buf!(w, pad);
151	        });
152	
153	        // Second block: all zeros except final 8 bytes = bit length
154	        // let mut pad2 = [0u8; 64];
155	        unroll!(8, {
156	            pad2[56 + I] = bitlen_bytes[I];
157	        });
158	
159	        process_block!(w, &mut state, {
160	            load_block_from_buf!(w, pad2);
161	        });
162	    }
163	
164	    state_to_hash(&state)
165	}
166	
167	/// Compute SHA-256 of exactly 80 bytes.
168	///
169	/// Produces two blocks:
170	/// - Block 1: bytes 0–63 of the input (all data)
171	/// - Block 2: bytes 64–79 (16 data bytes) + 0x80 + 47 zeros + 8-byte length (640 bits)
172	pub(crate) fn sha256_80bytes_old(data: &[u8; 80]) -> [u8; 32] {
173	    let mut state = SHA256_IV;
174	
175	    // ── Block 1: bytes 0–63 ──
176	    let mut w = [0u64; 64];
177	    for i in (0..16) {
178	        w[i] = be_u64_from_slice(data, i);
179	    }
180	    (&mut w);
181	    syscall_sha256_compress(&mut w, &mut state);
182	
183	    // ── Block 2: bytes 64–79 + padding + length ──
184	    // Layout: [data 16 bytes | 0x80 | 47× 0x00 | 8-byte big-endian length 640 = 0x280]
185	    let mut w = [0u64; 64];
186	    for i in (16..20) {
187	        w[i] = be_u64_from_slice(data, i);
188	    }
189	    // End of data; add "1" bit followed by "0" bits
190	    w[4] = 0x80000000;
191	    // Add length of data in bits; 640 == 0x280
192	    w[15] = 0x280;
193	
194	    syscall_sha256_extend(&mut w);
195	    syscall_sha256_compress(&mut w, &mut state);
196	    state_to_hash(&state)
197	}
198	
199	pub fn sha256_80bytes(data: &[u8; 80]) -> [u8; 32] {
200	    sha256_fixed!(data, 80)
201	}
202	
203	pub fn sha256_32bytes(data: &[u8; 32]) -> [u8; 32] {
204	    sha256_fixed!(data, 32)
205	}
206	/// Compute SHA-256 of exactly 32 bytes.
207	///
208	/// Produces one block:
209	/// bytes 0–31 (all data) + 0x80 + 23 zeros + 8-byte length (256 bits)
210	pub(crate) fn sha256_32bytes_old(data: &[u8; 32]) -> [u8; 32] {
211	    let mut state = SHA256_IV;
212	
213	    // ── Single block: 32 bytes + padding + length ──
214	    let mut w = [0u64; 64];
215	    for i in (0..8) {
216	        w[i] = be_u64_from_slice(data, i);
217	    }
218	    // End of data; add "1" bit followed by "0" bits
219	    w[8] = 0x80000000;
