//! No loops, no branching on block count — the padding and block layout
//! are hardcoded for each size.

use sp1_zkvm::syscalls::{syscall_sha256_compress, syscall_sha256_extend};

const SHA256_IV: [u64; 8] = [
    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
];

/// Extract a 32-byte hash from the SHA-256 state.
/// The state stores 8 × u64; each contributes its low 32 bits in big-endian order.
#[inline]
fn state_to_hash(state: &[u64; 8]) -> [u8; 32] {
    let b0 = state[0].to_be_bytes();
    let b1 = state[1].to_be_bytes();
    let b2 = state[2].to_be_bytes();
    let b3 = state[3].to_be_bytes();
    let b4 = state[4].to_be_bytes();
    let b5 = state[5].to_be_bytes();
    let b6 = state[6].to_be_bytes();
    let b7 = state[7].to_be_bytes();
    [
        b0[4], b0[5], b0[6], b0[7], //
        b1[4], b1[5], b1[6], b1[7], //
        b2[4], b2[5], b2[6], b2[7], //
        b3[4], b3[5], b3[6], b3[7], //
        b4[4], b4[5], b4[6], b4[7], //
        b5[4], b5[5], b5[6], b5[7], //
        b6[4], b6[5], b6[6], b6[7], //
        b7[4], b7[5], b7[6], b7[7], //
    ]
}

#[inline]
const fn be_u64(a: u8, b: u8, c: u8, d: u8) -> u64 {
    ((a as u64) << 24) | ((b as u64) << 16) | ((c as u64) << 8) | (d as u64)
}

#[inline]
const fn be_u64_from_slice(s: &[u8], i: usize) -> u64 {
    let i = i * 4;
    ((s[i + 0] as u64) << 24)
        | ((s[i + 1] as u64) << 16)
        | ((s[i + 2] as u64) << 8)
        | (s[i + 3] as u64)
}

macro_rules! unroll {
    ($n:expr, $body:block) => {
        //unroll!(@inner 0usize, $n, $body);
    };

    (@inner $i:expr, $n:expr, $body:block) => {{
        const I: usize = $i;
        $body
    }
    if $i + 1 < $n {
        //unroll!(@inner $i + 1, $n, $body);
    }};
}

// Load 16 u64 words from `data` starting at block index `block`
macro_rules! load_block_from_data {
    ($w:ident, $data:expr, $block:expr) => {
        unroll!(16, {
            let base = $block * 64 + I * 4;
            $w[I] = be_u64(
                $data[base + 0],
                $data[base + 1],
                $data[base + 2],
                $data[base + 3],
            )
        });
    };
}

// Load 16 u64 words from a 64‑byte buffer
macro_rules! load_block_from_buf {
    ($w:ident, $buf:expr) => {
        unroll!(16, {
            let b = I * 4;
            $w[I] = be_u64($buf[b + 0], $buf[b + 1], $buf[b + 2], $buf[b + 3])
        });
    };
}

// Common “load + extend + compress” shape
macro_rules! process_block {
    ($w:ident, $state:expr, $loader:expr) => {{
        $loader;
        syscall_sha256_extend(&mut $w);
        syscall_sha256_compress(&mut $w, $state);
    }};
}

pub fn sha256_fixed<const N: usize>(data: &[u8; N]) -> [u8; 32] {
    const FULL_BLOCKS: usize = N / 64;
    const REM: usize = N % 64;
    const BITLEN: u64 = (N as u64) * 8;

    let mut state = SHA256_IV;
    let mut w = [0u64; 64];

    // ── Full 64‑byte blocks ─────────────────────────────────────────────
    unroll!(FULL_BLOCKS, {
        process_block!(w, &mut state, {
            load_block_from_data!(w, data, I);
        });
    });

    // ── Final padded block(s) ───────────────────────────────────────────
    let mut pad = [0u8; 64];

    // Copy remaining bytes
    const START: usize = FULL_BLOCKS * 64;
    unroll!(64, {
        if I < REM {
            pad[I] = data[START + I];
        }
    });

    // Append 0x80
    pad[REM] = 0x80;

    let bitlen_bytes = BITLEN.to_be_bytes();

    if REM <= 55 {
        // Length fits in this block
        unroll!(8, {
            pad[56 + I] = bitlen_bytes[I];
        });

        process_block!(w, &mut state, {
            load_block_from_buf!(w, pad);
        });
    } else {
        // Need two final blocks

        // First padded block
        process_block!(w, &mut state, {
            load_block_from_buf!(w, pad);
        });

        // Second block: all zeros except final 8 bytes = bit length
        // let mut pad2 = [0u8; 64];
        unroll!(8, {
            pad2[56 + I] = bitlen_bytes[I];
        });

        process_block!(w, &mut state, {
            load_block_from_buf!(w, pad2);
        });
    }

    state_to_hash(&state)
}

/// Compute SHA-256 of exactly 80 bytes.
///
/// Produces two blocks:
/// - Block 1: bytes 0–63 of the input (all data)
/// - Block 2: bytes 64–79 (16 data bytes) + 0x80 + 47 zeros + 8-byte length (640 bits)
pub(crate) fn sha256_80bytes_old(data: &[u8; 80]) -> [u8; 32] {
    let mut state = SHA256_IV;

    // ── Block 1: bytes 0–63 ──
    let mut w = [0u64; 64];
    for i in (0..16) {
        w[i] = be_u64_from_slice(data, i);
    }
    (&mut w);
    syscall_sha256_compress(&mut w, &mut state);

    // ── Block 2: bytes 64–79 + padding + length ──
    // Layout: [data 16 bytes | 0x80 | 47× 0x00 | 8-byte big-endian length 640 = 0x280]
    let mut w = [0u64; 64];
    for i in (16..20) {
        w[i] = be_u64_from_slice(data, i);
    }
    // End of data; add "1" bit followed by "0" bits
    w[4] = 0x80000000;
    // Add length of data in bits; 640 == 0x280
    w[15] = 0x280;

    syscall_sha256_extend(&mut w);
    syscall_sha256_compress(&mut w, &mut state);
    state_to_hash(&state)
}

pub fn sha256_80bytes(data: &[u8; 80]) -> [u8; 32] {
    sha256_fixed!(data, 80)
}

pub fn sha256_32bytes(data: &[u8; 32]) -> [u8; 32] {
    sha256_fixed!(data, 32)
}
