pub fn sha256_fixed<const N: usize>(data: &[u8; N]) -> [u8; 32] {
    const FULL_BLOCKS: usize = N / 64;
    const REM: usize = N % 64;
    const BITLEN: u64 = (N as u64) * 8;

    let mut state = SHA256_IV;
    let mut w = [0u64; 64];

    // ── Full 64‑byte blocks ─────────────────────────────────────────────
    unroll!(FULL_BLOCKS, {
        process_block!(w, &mut state, {
            load_block_from_data!(w, data, I);
        });
    });

    // ── Final padded block(s) ───────────────────────────────────────────
    let mut pad = [0u8; 64];

    // Copy remaining bytes
    const START: usize = FULL_BLOCKS * 64;
    unroll!(64, {
        if I < REM {
            pad[I] = data[START + I];
        }
    });

    // Append 0x80
    pad[REM] = 0x80;

    let bitlen_bytes = BITLEN.to_be_bytes();

    if REM <= 55 {
        // Length fits in this block
        unroll!(8, {
            pad[56 + I] = bitlen_bytes[I];
        });

        process_block!(w, &mut state, {
            load_block_from_buf!(w, pad);
        });
    } else {
        // Need two final blocks

        // First padded block
        process_block!(w, &mut state, {
