1	//! SHA-256 via SP1 precompile syscalls.
2	//!
3	//! Specialized functions for the exact sizes we need:
4	//! - `sha256_80bytes`: hashes exactly 80 bytes (Bitcoin block header)
5	//! - `sha256_32bytes`: hashes exactly 32 bytes (intermediate hash output)
6	//! - `sha256_169bytes`: hashes exactly 169 bytes (minimal public values)
7	//! - `sha256_116bytes`: hashes exactly 116 bytes (private continuation state)
8	//! - `sha256d_80bytes`: hashes exactly 80 bytes with SHA256d
9	//!
10	//! No loops, no branching on block count — the padding and block layout
11	//! are hardcoded for each size.
12	
13	use sp1_zkvm::syscalls::{syscall_sha256_compress, syscall_sha256_extend};
14	
15	const SHA256_IV: [u64; 8] = [
16	    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
17	];
18	
19	/// Extract a 32-byte hash from the SHA-256 state.
20	/// The state stores 8 × u64; each contributes its low 32 bits in big-endian order.
21	#[inline]
22	fn state_to_hash(state: &[u64; 8]) -> [u8; 32] {
23	    let b0 = state[0].to_be_bytes();
24	    let b1 = state[1].to_be_bytes();
25	    let b2 = state[2].to_be_bytes();
26	    let b3 = state[3].to_be_bytes();
27	    let b4 = state[4].to_be_bytes();
28	    let b5 = state[5].to_be_bytes();
29	    let b6 = state[6].to_be_bytes();
30	    let b7 = state[7].to_be_bytes();
31	    [
32	        b0[4], b0[5], b0[6], b0[7], //
33	        b1[4], b1[5], b1[6], b1[7], //
34	        b2[4], b2[5], b2[6], b2[7], //
35	        b3[4], b3[5], b3[6], b3[7], //
36	        b4[4], b4[5], b4[6], b4[7], //
37	        b5[4], b5[5], b5[6], b5[7], //
38	        b6[4], b6[5], b6[6], b6[7], //
39	        b7[4], b7[5], b7[6], b7[7], //
40	    ]
41	}
42	
43	#[inline]
44	const fn be_u64(a: u8, b: u8, c: u8, d: u8) -> u64 {
45	    ((a as u64) << 24) | ((b as u64) << 16) | ((c as u64) << 8) | (d as u64)
46	}
47	
48	#[inline]
49	const fn be_u64_from_slice(s: &[u8], i: usize) -> u64 {
50	    let i = i * 4;
51	    ((s[i + 0] as u64) << 24)
52	        | ((s[i + 1] as u64) << 16)
53	        | ((s[i + 2] as u64) << 8)
54	        | (s[i + 3] as u64)
55	}
56	
57	macro_rules! unroll {
58	    ($n:expr, $body:block) => {
59	        //unroll!(@inner 0usize, $n, $body);
60	    };
61	
62	    (@inner $i:expr, $n:expr, $body:block) => {{
63	        const I: usize = $i;
64	        $body
65	    }
66	    if $i + 1 < $n {
67	        //unroll!(@inner $i + 1, $n, $body);
68	    }};
69	}
70	
71	// Load 16 u64 words from `data` starting at block index `block`
72	macro_rules! load_block_from_data {
73	    ($w:ident, $data:expr, $block:expr) => {
74	        unroll!(16, {
75	            let base = $block * 64 + I * 4;
76	            $w[I] = be_u64(
77	                $data[base + 0],
78	                $data[base + 1],
79	                $data[base + 2],
80	                $data[base + 3],
81	            )
82	        });
83	    };
84	}
85	
86	// Load 16 u64 words from a 64‑byte buffer
87	macro_rules! load_block_from_buf {
88	    ($w:ident, $buf:expr) => {
89	        unroll!(16, {
90	            let b = I * 4;
91	            $w[I] = be_u64($buf[b + 0], $buf[b + 1], $buf[b + 2], $buf[b + 3])
92	        });
93	    };
94	}
95	
96	// Common “load + extend + compress” shape
97	macro_rules! process_block {
98	    ($w:ident, $state:expr, $loader:expr) => {{
99	        $loader;
100	        syscall_sha256_extend(&mut $w);
101	        syscall_sha256_compress(&mut $w, $state);
102	    }};
103	}
104	
105	
106	/// Compute SHA-256 of exactly 80 bytes.
107	///
108	/// Produces two blocks:
109	/// - Block 1: bytes 0–63 of the input (all data)
110	/// - Block 2: bytes 64–79 (16 data bytes) + 0x80 + 47 zeros + 8-byte length (640 bits)
111	pub(crate) fn sha256_80bytes_old(data: &[u8; 80]) -> [u8; 32] {
112	    let mut state = SHA256_IV;
113	
114	    // ── Block 1: bytes 0–63 ──
115	    let mut w = [0u64; 64];
116	    for i in (0..16) {
117	        w[i] = be_u64_from_slice(data, i);
118	    }
119	    (&mut w);
120	    syscall_sha256_compress(&mut w, &mut state);
121	
122	    // ── Block 2: bytes 64–79 + padding + length ──
123	    // Layout: [data 16 bytes | 0x80 | 47× 0x00 | 8-byte big-endian length 640 = 0x280]
124	    let mut w = [0u64; 64];
125	    for i in (16..20) {
126	        w[i] = be_u64_from_slice(data, i);
127	    }
128	    // End of data; add "1" bit followed by "0" bits
129	    w[4] = 0x80000000;
130	    // Add length of data in bits; 640 == 0x280
131	    w[15] = 0x280;
132	
133	    syscall_sha256_extend(&mut w);
134	    syscall_sha256_compress(&mut w, &mut state);
135	    state_to_hash(&state)
136	}
137	
138	pub fn sha256_80bytes(data: &[u8; 80]) -> [u8; 32] {
139	    sha256_80bytes_old(data)
140	}
141	
142	pub fn sha256_32bytes(data: &[u8; 32]) -> [u8; 32] {
143	    sha256_32bytes_old(data)
144	}
145	/// Compute SHA-256 of exactly 32 bytes.
146	///
147	/// Produces one block:
148	/// bytes 0–31 (all data) + 0x80 + 23 zeros + 8-byte length (256 bits)
149	pub(crate) fn sha256_32bytes_old(data: &[u8; 32]) -> [u8; 32] {
150	    let mut state = SHA256_IV;
151	
152	    // ── Single block: 32 bytes + padding + length ──
153	    let mut w = [0u64; 64];
154	    for i in (0..8) {
155	        w[i] = be_u64_from_slice(data, i);
156	    }
157	    // End of data; add "1" bit followed by "0" bits
158	    w[8] = 0x80000000;
159	    // Add length of data in bits; 256 == 0x100
160	    w[15] = 0x100;
161	
162	    syscall_sha256_extend(&mut w);
163	    syscall_sha256_compress(&mut w, &mut state);
164	    state_to_hash(&state)
165	}
166	
167	/// Compute SHA-256 of exactly 169 bytes.
168	///
169	/// Produces three blocks:
170	/// - Block 1: bytes 0–63
171	/// - Block 2: bytes 64–127
172	/// - Block 3: bytes 128–168 (41 data bytes) + 0x80 + zeros + 8-byte length (1352 bits = 0x548)
173	pub(crate) fn sha256_169bytes(data: &[u8; 169]) -> [u8; 32] {
174	    let mut state = SHA256_IV;
175	
176	    // ── Block 1: bytes 0–63 ──
177	    let mut w = [0u64; 64];
178	    w[0] = be_u64(data[0], data[1], data[2], data[3]);
179	    w[1] = be_u64(data[4], data[5], data[6], data[7]);
180	    w[2] = be_u64(data[8], data[9], data[10], data[11]);
181	    w[3] = be_u64(data[12], data[13], data[14], data[15]);
182	    w[4] = be_u64(data[16], data[17], data[18], data[19]);
183	    w[5] = be_u64(data[20], data[21], data[22], data[23]);
184	    w[6] = be_u64(data[24], data[25], data[26], data[27]);
185	    w[7] = be_u64(data[28], data[29], data[30], data[31]);
186	    w[8] = be_u64(data[32], data[33], data[34], data[35]);
187	    w[9] = be_u64(data[36], data[37], data[38], data[39]);
188	    w[10] = be_u64(data[40], data[41], data[42], data[43]);
189	    w[11] = be_u64(data[44], data[45], data[46], data[47]);
190	    w[12] = be_u64(data[48], data[49], data[50], data[51]);
191	    w[13] = be_u64(data[52], data[53], data[54], data[55]);
192	    w[14] = be_u64(data[56], data[57], data[58], data[59]);
193	    w[15] = be_u64(data[60], data[61], data[62], data[63]);
194	    syscall_sha256_extend(&mut w);
195	    syscall_sha256_compress(&mut w, &mut state);
196	
197	    // ── Block 2: bytes 64–127 ──
