const fn be_u64(a: u8, b: u8, c: u8, d: u8) -> u64 {
    ((a as u64) << 24) | ((b as u64) << 16) | ((c as u64) << 8) | (d as u64)
}

#[inline]
const fn be_u64_from_slice(s: &[u8], i: usize) -> u64 {
    let i = i * 4;
    ((s[i] as u64) << 24)
        | ((s[i + 1] as u64) << 16)
        | ((s[i + 2] as u64) << 8)
